{
  "$schema": "./node_modules/oxlint/configuration_schema.json",
  "plugins": ["react", "typescript", "oxc"],
  "rules": {
    "react/rules-of-hooks": "error",
    "react/only-export-components": ["warn", { "allowConstantExport": true }]
  }
}

@echo off
cd /d "%~dp0"
npm run desktop:dev

const { app, BrowserWindow, dialog } = require("electron");
const path = require("node:path");
const { startStaticServer } = require("./staticServer.cjs");

const isDev = !app.isPackaged;
const devUrl = process.env.ELECTRON_START_URL || "http://127.0.0.1:5174";
const distRoot = path.join(__dirname, "..", "dist");

/** @type {import("node:http").Server | null} */
let staticServer = null;
let appUrl = devUrl;

async function ensureAppUrl() {
  if (isDev) {
    appUrl = devUrl;
    return;
  }
  if (appUrl && staticServer) return;
  const { server, url } = await startStaticServer(distRoot);
  staticServer = server;
  appUrl = url;
}

function createWindow() {
  const mainWindow = new BrowserWindow({
    width: 1440,
    height: 900,
    minWidth: 1024,
    minHeight: 700,
    backgroundColor: "#000000",
    autoHideMenuBar: true,
    webPreferences: {
      contextIsolation: true,
      nodeIntegration: false,
    },
  });

  mainWindow.webContents.on("did-fail-load", (_event, code, description, validatedURL) => {
    dialog.showErrorBox(
      "Smash Drums Editor failed to load",
      `${description} (${code})\n\nURL: ${validatedURL || appUrl}`
    );
  });

  mainWindow.loadURL(appUrl).catch((err) => {
    dialog.showErrorBox("Smash Drums Editor failed to load", String(err));
  });
}

app.whenReady().then(async () => {
  try {
    await ensureAppUrl();
  } catch (err) {
    dialog.showErrorBox("Smash Drums Editor failed to start", String(err));
    app.quit();
    return;
  }
  createWindow();
  app.on("activate", () => {
    if (BrowserWindow.getAllWindows().length === 0) createWindow();
  });
});

app.on("will-quit", () => {
  if (staticServer) {
    staticServer.close();
    staticServer = null;
  }
});

app.on("window-all-closed", () => {
  if (process.platform !== "darwin") app.quit();
});

const http = require("node:http");
const fs = require("node:fs");
const path = require("node:path");

const MIME_TYPES = {
  ".html": "text/html; charset=utf-8",
  ".js": "text/javascript; charset=utf-8",
  ".mjs": "text/javascript; charset=utf-8",
  ".css": "text/css; charset=utf-8",
  ".svg": "image/svg+xml",
  ".json": "application/json",
  ".png": "image/png",
  ".woff2": "font/woff2",
  ".ogg": "audio/ogg",
  ".mp3": "audio/mpeg",
  ".wav": "audio/wav",
};

function contentType(filePath) {
  return MIME_TYPES[path.extname(filePath).toLowerCase()] || "application/octet-stream";
}

function resolveFile(root, requestPath) {
  const relative = requestPath.replace(/^\/+/, "") || "index.html";
  const resolved = path.normalize(path.join(root, relative));
  if (!resolved.startsWith(root)) return null;
  return resolved;
}

/** Serve dist/ over http://127.0.0.1 so blob audio matches the Vite web app. */
function startStaticServer(rootDir) {
  return new Promise((resolve, reject) => {
    const root = path.normalize(rootDir);
    const server = http.createServer((req, res) => {
      try {
        const pathname = decodeURIComponent(
          new URL(req.url || "/", "http://127.0.0.1").pathname
        );
        let filePath = resolveFile(root, pathname);
        if (!filePath || !fs.existsSync(filePath) || fs.statSync(filePath).isDirectory()) {
          filePath = path.join(root, "index.html");
        }
        if (!fs.existsSync(filePath)) {
          res.writeHead(404);
          res.end("Not found");
          return;
        }
        res.writeHead(200, {
          "Content-Type": contentType(filePath),
          "Cache-Control": "no-cache",
        });
        fs.createReadStream(filePath).pipe(res);
      } catch {
        res.writeHead(500);
        res.end();
      }
    });

    server.on("error", reject);
    server.listen(0, "127.0.0.1", () => {
      const addr = server.address();
      const port = typeof addr === "object" && addr ? addr.port : 0;
      resolve({ server, url: `http://127.0.0.1:${port}/` });
    });
  });
}

module.exports = { startStaticServer };

const path = require("node:path");

const outputDir = path.join(__dirname, "release");

/** @type {import('electron-builder').Configuration} */
module.exports = {
  appId: "com.smashdrums.editor",
  productName: "Smash Drums Editor",
  directories: {
    output: outputDir,
  },
  files: ["dist/**/*", "electron/**/*", "package.json"],
  asar: true,
  win: {
    target: [
      {
        target: "portable",
        arch: ["x64"],
      },
    ],
    icon: "public/app-icon.jpg",
    artifactName: "Smash-Drums-Editor-${version}-portable.exe",
  },
};

