const fs = require("node:fs");
const path = require("node:path");
const { execSync } = require("node:child_process");

const outputDir = path.join(__dirname, "..", "release");

function sleep(ms) {
  try {
    execSync(`powershell -NoProfile -Command "Start-Sleep -Milliseconds ${ms}"`, {
      stdio: "ignore",
    });
  } catch {
    /* ignore */
  }
}

function tryKillLocks() {
  if (process.platform !== "win32") return;
  for (const image of ["electron.exe", "Smash Drums Editor.exe"]) {
    try {
      execSync(`taskkill /F /IM ${image} /T 2>nul`, { stdio: "ignore" });
    } catch {
      /* not running */
    }
  }
}

function removeDir(dir) {
  if (!fs.existsSync(dir)) return true;
  for (let attempt = 0; attempt < 5; attempt++) {
    try {
      fs.rmSync(dir, { recursive: true, force: true, maxRetries: 3, retryDelay: 200 });
      return true;
    } catch {
      sleep(400);
    }
  }
  return false;
}

tryKillLocks();
sleep(300);

for (const name of ["win-unpacked.tmp", "win-unpacked"]) {
  const target = path.join(outputDir, name);
  if (!removeDir(target)) {
    console.warn(`Warning: could not fully remove ${target}`);
  }
}

fs.mkdirSync(outputDir, { recursive: true });
console.log(`Release output: ${outputDir}`);

const { downloadArtifact } = require("@electron/get");
const extract = require("extract-zip");
const fs = require("node:fs");
const path = require("node:path");

const electronDir = path.join(__dirname, "..", "node_modules", "electron");
const distDir = path.join(electronDir, "dist");
const pathFile = path.join(electronDir, "path.txt");
const { version } = require(path.join(electronDir, "package.json"));

const platformPath = process.platform === "win32" ? "electron.exe" : "electron";

function isInstalled() {
  try {
    const installedVersion = fs
      .readFileSync(path.join(distDir, "version"), "utf8")
      .replace(/^v/, "")
      .trim();
    const installedPath = fs.readFileSync(pathFile, "utf8").trim();
    return (
      installedVersion === version &&
      installedPath === platformPath &&
      fs.existsSync(path.join(distDir, platformPath))
    );
  } catch {
    return false;
  }
}

async function main() {
  if (process.env.ELECTRON_SKIP_BINARY_DOWNLOAD || isInstalled()) return;

  const zipPath = await downloadArtifact({
    version,
    artifactName: "electron",
    platform: process.env.npm_config_platform || process.platform,
    arch: process.env.npm_config_arch || process.arch,
  });

  fs.rmSync(distDir, { recursive: true, force: true });
  fs.mkdirSync(distDir, { recursive: true });
  await extract(zipPath, { dir: path.resolve(distDir) });
  fs.writeFileSync(pathFile, platformPath);
  fs.writeFileSync(path.join(distDir, "version"), `v${version}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

