import { useEffect, useRef, useState } from "react";
import { laneColumnIndex } from "../types/meta";
import { useEditorStore } from "../store/useEditorStore";
import { seekChartTime } from "../utils/audioElement";
import { getSongOffset } from "../utils/offset";
import { beatToTick, RESOLUTION } from "../utils/resolution";
import { songExtentTicks } from "../utils/songExtent";
import { HIGHWAY_THEME as T } from "../theme/highway";
import { beatToTime, timeToBeat } from "../utils/timing";
import { drawMirroredWaveEnvelope, WAVE_WIDTH_FRAC } from "../utils/waveDraw";
import { buildWaveformByTick, type WavePeak } from "../utils/waveform";
import { getMainWaveformBuffer } from "../utils/audioSource";
import type { TimingAnchor } from "../types/meta";

const STRIKE_OFFSET = 150;
const LANE_HEADER_H = 44;

/** Match highway: future (high ticks) at top, song start at bottom. */
function tickToY(tick: number, totalTicks: number, height: number): number {
  if (totalTicks <= 0) return height;
  return height - (tick / totalTicks) * height;
}

function overviewWaveSamples(
  peaks: WavePeak[],
  totalTicks: number,
  h: number,
  chartTime: number,
  timing: TimingAnchor[],
  mode: "past" | "future"
) {
  return peaks
    .filter((p) => {
      if (p.amp < 0.01 || p.tick > totalTicks) return false;
      const noteTime = beatToTime(p.tick / RESOLUTION, timing);
      return mode === "past" ? noteTime <= chartTime : noteTime > chartTime;
    })
    .map((p) => ({ pos: tickToY(p.tick, totalTicks, h), amp: p.amp }));
}

export function SongOverview() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const wrapRef = useRef<HTMLDivElement>(null);
  const wavePeaksRef = useRef<WavePeak[]>([]);
  const draggingRef = useRef(false);
  const [scrubbing, setScrubbing] = useState(false);

  const {
    meta,
    charts,
    difficulty,
    duration,
    audioBuffer,
    drumsAudioBuffer,
    audioSource,
    scrollTick,
    pixelsPerTick,
    isPlaying,
    currentTime,
  } = useEditorStore();

  useEffect(() => {
    const buffer = getMainWaveformBuffer(useEditorStore.getState());
    if (buffer) {
      wavePeaksRef.current = buildWaveformByTick(
        buffer,
        meta.SongTiming,
        getSongOffset(meta),
        16
      );
    } else {
      wavePeaksRef.current = [];
    }
  }, [audioBuffer, drumsAudioBuffer, audioSource, meta.SongTiming, meta.SongOffsetSeconds]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    let raf = 0;

    const draw = () => {
      raf = requestAnimationFrame(draw);

      const wrap = wrapRef.current;
      const ctx = canvas.getContext("2d");
      if (!ctx || !wrap) return;

      const dpr = window.devicePixelRatio || 1;
      const w = wrap.clientWidth;
      const h = wrap.clientHeight;
      if (w < 2 || h < 2) return;

      const cw = Math.max(1, Math.floor(w * dpr));
      const ch = Math.max(1, Math.floor(h * dpr));
      if (canvas.width !== cw || canvas.height !== ch) {
        canvas.width = cw;
        canvas.height = ch;
        canvas.style.width = `${w}px`;
        canvas.style.height = `${h}px`;
      }

      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, w, h);

      const state = useEditorStore.getState();
      const totalTicks = songExtentTicks(state.meta, state.charts, state.duration);
      const notes = state.charts[state.difficulty];
      const ppt = state.pixelsPerTick;
      const timing = state.meta.SongTiming;
      const offset = getSongOffset(state.meta);

      const audio = document.getElementById("editor-audio") as HTMLAudioElement | null;
      let chartTime = state.currentTime;
      if (state.isPlaying && audio && !audio.muted) {
        chartTime = audio.currentTime + offset;
      }

      const playBeat = timeToBeat(chartTime, timing);
      const playTick = playBeat * RESOLUTION;
      const activeScroll = state.isPlaying ? playTick : state.scrollTick;

      const sy = h - STRIKE_OFFSET;
      const viewTop = activeScroll + (sy - LANE_HEADER_H) / ppt;
      const viewBottom = Math.max(0, activeScroll - (h - sy + 80) / ppt);

      const cx = w / 2;
      const maxHalf = w * WAVE_WIDTH_FRAC;
      const peaks = wavePeaksRef.current;

      if (peaks.length > 0) {
        drawMirroredWaveEnvelope(
          ctx,
          overviewWaveSamples(peaks, totalTicks, h, chartTime, timing, "future"),
          cx,
          maxHalf,
          "future"
        );
        drawMirroredWaveEnvelope(
          ctx,
          overviewWaveSamples(peaks, totalTicks, h, chartTime, timing, "past"),
          cx,
          maxHalf,
          "past"
        );
      } else {
        ctx.fillStyle = "rgba(255,255,255,0.2)";
        ctx.font = "10px Inter, sans-serif";
        ctx.textAlign = "center";
        ctx.fillText("Load audio", w / 2, h / 2);
      }

      // Phase markers
      for (const ph of state.meta.SongPhases) {
        const y = tickToY(beatToTick(ph.beat), totalTicks, h);
        ctx.fillStyle = "rgba(129, 140, 248, 0.5)";
        ctx.fillRect(4, y, w - 8, 1);
      }

      // Offset / audio start
      if (offset > 0) {
        const offsetTick = beatToTick(timeToBeat(offset, timing));
        const y = tickToY(offsetTick, totalTicks, h);
        ctx.fillStyle = "rgba(255, 190, 60, 0.75)";
        ctx.fillRect(0, y, w, 2);
      }

      // Note density
      for (const note of notes) {
        const tick = beatToTick(note.Beat);
        if (tick > totalTicks) continue;
        const y = tickToY(tick, totalTicks, h);
        const col = laneColumnIndex(note.Id);
        const x = 8 + (col / 5) * (w - 16);
        ctx.fillStyle = "rgba(255, 255, 255, 0.45)";
        ctx.fillRect(x, y, 2, 2);
      }

      // Viewport band
      const topY = tickToY(viewTop, totalTicks, h);
      const bottomY = tickToY(viewBottom, totalTicks, h);
      const boxTop = Math.max(0, topY);
      const boxBottom = Math.min(h, bottomY);
      const boxH = Math.max(10, boxBottom - boxTop);

      ctx.fillStyle = `rgba(${T.magentaRgb}, 0.08)`;
      ctx.fillRect(0, boxTop, w, boxH);
      ctx.strokeStyle = `rgba(${T.neonRgb}, 0.32)`;
      ctx.lineWidth = 1;
      ctx.strokeRect(0.5, boxTop + 0.5, w - 1, boxH - 1);

      // Playhead — bright vertical scrub line through the waveform
      const playY = tickToY(playTick, totalTicks, h);
      if (playY >= 0 && playY <= h) {
        ctx.save();
        ctx.shadowColor = T.magenta;
        ctx.shadowBlur = 14;
        ctx.strokeStyle = `rgba(${T.neonRgb}, 0.95)`;
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.moveTo(0, playY);
        ctx.lineTo(w, playY);
        ctx.stroke();
        ctx.restore();
      }

      ctx.fillStyle = "rgba(255, 255, 255, 0.06)";
      ctx.fillRect(0, 0, w, 1);
      ctx.fillRect(0, h - 1, w, 1);
    };

    draw();
    return () => cancelAnimationFrame(raf);
  }, [
    meta.SongTiming,
    meta.SongPhases,
    meta.SongOffsetSeconds,
    charts,
    difficulty,
    duration,
    scrollTick,
    pixelsPerTick,
    isPlaying,
    currentTime,
    audioBuffer,
    drumsAudioBuffer,
    audioSource,
  ]);

  const jumpFromClientY = (clientY: number) => {
    const wrap = wrapRef.current;
    if (!wrap) return;

    const state = useEditorStore.getState();
    const rect = wrap.getBoundingClientRect();
    const y = Math.max(0, Math.min(rect.height, clientY - rect.top));
    const ratio = rect.height > 0 ? 1 - y / rect.height : 0;
    const totalTicks = songExtentTicks(state.meta, state.charts, state.duration);
    const tick = ratio * totalTicks;
    const chartTime = beatToTime(tick / RESOLUTION, state.meta.SongTiming);
    const maxChart =
      state.duration > 0
        ? state.duration + getSongOffset(state.meta)
        : chartTime;
    seekChartTime(Math.max(0, Math.min(chartTime, maxChart)));
  };

  useEffect(() => {
    const onMove = (e: MouseEvent) => {
      if (!draggingRef.current) return;
      jumpFromClientY(e.clientY);
    };
    const onUp = () => {
      if (draggingRef.current) {
        draggingRef.current = false;
        setScrubbing(false);
      }
    };
    window.addEventListener("mousemove", onMove);
    window.addEventListener("mouseup", onUp);
    return () => {
      window.removeEventListener("mousemove", onMove);
      window.removeEventListener("mouseup", onUp);
    };
  }, []);

  useEffect(() => {
    const el = wrapRef.current;
    if (!el) return;

    const onWheel = (e: WheelEvent) => {
      e.preventDefault();
      const state = useEditorStore.getState();
      const totalTicks = songExtentTicks(state.meta, state.charts, state.duration);
      const timing = state.meta.SongTiming;
      const offset = getSongOffset(state.meta);
      const audio = document.getElementById("editor-audio") as HTMLAudioElement | null;

      let chartTime = state.currentTime;
      if (state.isPlaying && audio && !audio.muted) {
        chartTime = audio.currentTime + offset;
      }

      const step = (totalTicks / RESOLUTION / 80) * (e.deltaY > 0 ? -1 : 1);
      const nextBeat = timeToBeat(chartTime, timing) + step;
      const nextChart = beatToTime(Math.max(0, nextBeat), timing);
      const maxChart =
        state.duration > 0 ? state.duration + offset : nextChart;
      seekChartTime(Math.max(0, Math.min(nextChart, maxChart)));
    };

    el.addEventListener("wheel", onWheel, { passive: false });
    return () => el.removeEventListener("wheel", onWheel);
  }, []);

  const startScrub = (clientY: number) => {
    draggingRef.current = true;
    setScrubbing(true);
    jumpFromClientY(clientY);
  };

  return (
    <div
      className={`song-overview${scrubbing ? " is-scrubbing" : ""}`}
      ref={wrapRef}
      title="Click, drag, or scroll to scrub through the song"
      onMouseDown={(e) => startScrub(e.clientY)}
      onTouchStart={(e) => {
        if (e.touches[0]) startScrub(e.touches[0].clientY);
      }}
      onTouchMove={(e) => {
        if (draggingRef.current && e.touches[0]) {
          e.preventDefault();
          jumpFromClientY(e.touches[0].clientY);
        }
      }}
      onTouchEnd={() => {
        draggingRef.current = false;
        setScrubbing(false);
      }}
    >
      <canvas ref={canvasRef} className="song-overview-canvas" />
    </div>
  );
}

import { clampPhaseId, PHASE_TYPES, phaseById, sortSongPhases } from "../types/meta";
import { useEditorStore } from "../store/useEditorStore";

export function SongPhasesPanel({ embedded = false }: { embedded?: boolean }) {
  const {
    meta,
    placementMode,
    pendingPhasePlacement,
    updatePhase,
    addPhase,
    addPhaseAtPlayhead,
    removePhase,
    setPlacementMode,
    setPendingPhasePlacement,
  } = useEditorStore();
  const phases = sortSongPhases(meta.SongPhases);
  const placing = placementMode === "phase";

  const togglePlaceOnGrid = () => {
    setPlacementMode(placing ? null : "phase");
  };

  const content = (
    <>
      <div className="placement-config placement-config-compact">
        <div className="field-grid">
          <label>
            Type
            <select
              value={pendingPhasePlacement.phase}
              onChange={(e) =>
                setPendingPhasePlacement({ phase: clampPhaseId(Number(e.target.value)) })
              }
            >
              {PHASE_TYPES.map((t) => (
                <option key={t.id} value={t.id}>
                  {t.id} — {t.label}
                </option>
              ))}
            </select>
          </label>
          <label>
            Label
            <input
              value={pendingPhasePlacement.phaseName}
              onChange={(e) => setPendingPhasePlacement({ phaseName: e.target.value })}
            />
          </label>
        </div>
        <label>
          Intensity ({Math.round(pendingPhasePlacement.power * 100)}%)
          <input
            type="range"
            min={0}
            max={1}
            step={0.05}
            value={pendingPhasePlacement.power}
            onChange={(e) =>
              setPendingPhasePlacement({ power: Number(e.target.value) })
            }
          />
        </label>
        <button
          className={`btn btn-accent placement-btn${placing ? " is-active" : ""}`}
          type="button"
          onClick={togglePlaceOnGrid}
        >
          {placing ? "Placing…" : "Place on grid"}
        </button>
      </div>

      <ul className="phase-list">
        {phases.map((ph, index) => {
          const type = phaseById(ph.phase);
          return (
            <li key={`${ph.beat}-${index}`} className="phase-item">
              <div className="phase-item-head">
                <span
                  className="phase-badge"
                  style={{ background: type.color + "33", color: type.color }}
                >
                  {type.label}
                </span>
                <button
                  className="phase-remove"
                  type="button"
                  title="Remove phase"
                  disabled={phases.length <= 1}
                  onClick={() => removePhase(index)}
                >
                  ×
                </button>
              </div>

              <div className="phase-fields-row">
                <label>
                  Beat
                  <input
                    type="number"
                    min={0}
                    step={0.25}
                    value={ph.beat}
                    onChange={(e) => updatePhase(index, { beat: Number(e.target.value) })}
                  />
                </label>
                <label>
                  Type
                  <select
                    value={ph.phase}
                    onChange={(e) =>
                      updatePhase(index, { phase: clampPhaseId(Number(e.target.value)) })
                    }
                  >
                    {PHASE_TYPES.map((t) => (
                      <option key={t.id} value={t.id}>
                        {t.id} — {t.label}
                      </option>
                    ))}
                  </select>
                </label>
              </div>

              <label>
                Intensity ({Math.round(ph.power * 100)}%)
                <input
                  type="range"
                  min={0}
                  max={1}
                  step={0.05}
                  value={ph.power}
                  onChange={(e) => updatePhase(index, { power: Number(e.target.value) })}
                />
              </label>
            </li>
          );
        })}
      </ul>

      <div className="btn-group phase-actions">
        <button className="btn" type="button" onClick={addPhase}>
          Add
        </button>
        <button className="btn btn-accent" type="button" onClick={addPhaseAtPlayhead}>
          At playhead
        </button>
      </div>
    </>
  );

  if (embedded) {
    return <div className="tab-content">{content}</div>;
  }

  return (
    <section className="panel">
      <h3>Song Phases</h3>
      <p className="hint">Musical sections — exported in [Events]</p>
      {content}
    </section>
  );
}

import type { TimingAnchor } from "../types/meta";
import { useEditorStore } from "../store/useEditorStore";
import { beatToTick, formatTick, RESOLUTION } from "../utils/resolution";
import { bpmAtAnchor, sortTimingAnchors } from "../utils/timing";

export function TimingAnchorsPanel({ embedded = false }: { embedded?: boolean }) {
  const {
    meta,
    placementMode,
    updateAnchor,
    addAnchor,
    addAnchorAtPlayhead,
    removeAnchor,
    setPlacementMode,
  } = useEditorStore();

  const anchors = sortTimingAnchors(meta.SongTiming);
  const placing = placementMode === "anchor";

  const togglePlaceOnGrid = () => {
    setPlacementMode(placing ? null : "anchor");
  };

  const content = (
    <>
      <button
        className={`btn btn-accent placement-btn${placing ? " is-active" : ""}`}
        type="button"
        onClick={togglePlaceOnGrid}
      >
        {placing ? "Placing…" : "Place on grid"}
      </button>

      <ul className="phase-list anchor-list">
        {anchors.map((anchor, index) => (
          <AnchorItem
            key={`${anchor.beat}-${anchor.timer}-${index}`}
            anchor={anchor}
            index={index}
            anchors={anchors}
            canRemove={anchors.length > 2}
            onUpdate={(patch) => updateAnchor(index, patch)}
            onRemove={() => removeAnchor(index)}
          />
        ))}
      </ul>

      <div className="btn-group phase-actions">
        <button className="btn" type="button" onClick={addAnchor}>
          Add
        </button>
        <button className="btn btn-accent" type="button" onClick={addAnchorAtPlayhead}>
          At playhead
        </button>
      </div>
    </>
  );

  if (embedded) {
    return <div className="tab-content">{content}</div>;
  }

  return (
    <section className="panel">
      <h3>Timing Anchors</h3>
      <p className="hint">Beat/time sync — exported in [SyncTrack]</p>
      {content}
    </section>
  );
}

function AnchorItem({
  anchor,
  index,
  anchors,
  canRemove,
  onUpdate,
  onRemove,
}: {
  anchor: TimingAnchor;
  index: number;
  anchors: TimingAnchor[];
  canRemove: boolean;
  onUpdate: (patch: Partial<TimingAnchor>) => void;
  onRemove: () => void;
}) {
  const tick = beatToTick(anchor.beat);
  const bpm =
    index < anchors.length - 1
      ? Math.round(bpmAtAnchor(anchors, index) * 10) / 10
      : null;

  return (
    <li className="phase-item anchor-item">
      <div className="phase-item-head">
        <span className="anchor-badge">Tick {formatTick(tick)}</span>
        <button
          className="phase-remove"
          type="button"
          title="Remove anchor"
          disabled={!canRemove}
          onClick={onRemove}
        >
          ×
        </button>
      </div>

      <div className="phase-fields-row">
        <label>
          Beat
          <input
            type="number"
            min={0}
            step={1 / RESOLUTION}
            value={anchor.beat}
            onChange={(e) => onUpdate({ beat: Math.max(0, Number(e.target.value)) })}
          />
        </label>
        <label>
          Time (s)
          <input
            type="number"
            min={0}
            step={0.001}
            value={anchor.timer}
            onChange={(e) => onUpdate({ timer: Math.max(0, Number(e.target.value)) })}
          />
        </label>
      </div>

      {bpm !== null && (
        <p className="hint anchor-meta hint-inline">{bpm} BPM → next</p>
      )}
    </li>
  );
}

import { useEffect, useRef } from "react";
import { useEditorStore } from "../store/useEditorStore";
import { seekChartTime, seekToStrikeBar } from "../utils/audioElement";
import {
  activeSourceLabel,
  getActiveAudioUrl,
  getActiveDuration,
} from "../utils/audioSource";
import {
  playEditorAudioAt,
  syncAudioPlaybackRate,
  syncAudioVolume,
  waitForAudioSeek,
} from "../utils/audioPlayback";
import {
  chartToAudioTime,
  getSongOffset,
  isInSilentLeadIn,
  offsetFromMs,
  OFFSET_NUDGE_FINE_MS,
} from "../utils/offset";
import { RESOLUTION, beatToTick, formatTick } from "../utils/resolution";
import { bpmFromAnchors } from "../utils/timing";
import { beatToTime, timeToBeat } from "../utils/timing";

export function Toolbar() {
  const {
    audioUrl,
    drumsAudioUrl,
    audioSource,
    audioFileName,
    drumsAudioFileName,
    currentTime,
    scrollTick,
    isPlaying,
    meta,
    loadAudio,
    loadDrumsAudio,
    loadMeta,
    exportMeta,
    exportChart,
    setCurrentTime,
    setIsPlaying,
    setScrollTick,
    setAudioSource,
    nudgeOffset,
    goToChartStart,
    playbackSpeed,
    songVolume,
    audioBuffer,
    bpmDetecting,
    bpmConfidence,
    setBpm,
    detectBpmFromAudio,
  } = useEditorStore();

  const audioRef = useRef<HTMLAudioElement>(null);
  const rafRef = useRef(0);
  const lastFrameRef = useRef(0);

  const activeAudioUrl = getActiveAudioUrl({
    audioSource,
    audioUrl,
    drumsAudioUrl,
  });
  const playingSource = activeSourceLabel({ audioSource, drumsAudioUrl });
  const canPlay = Boolean(activeAudioUrl);

  const chartTime = isPlaying
    ? currentTime
    : beatToTime(scrollTick / RESOLUTION, meta.SongTiming);
  const offset = getSongOffset(meta);
  const inSilence = isInSilentLeadIn(chartTime, offset);
  const audioTime = chartToAudioTime(chartTime, offset);

  const togglePlay = () => {
    const audio = audioRef.current;
    if (!audio || !activeAudioUrl) return;
    if (isPlaying) {
      audio.pause();
      const pausedChart =
        !audio.muted ? audio.currentTime + getSongOffset(meta) : chartTime;
      setCurrentTime(pausedChart);
      const beat = timeToBeat(pausedChart, meta.SongTiming);
      setScrollTick(beat * RESOLUTION);
      setIsPlaying(false);
    } else {
      seekToStrikeBar();
      const { currentTime: strikeChartTime, meta: m } = useEditorStore.getState();
      const off = getSongOffset(m);
      const silent = isInSilentLeadIn(strikeChartTime, off);
      if (silent) {
        audio.muted = true;
        void waitForAudioSeek(audio, 0);
      } else {
        audio.muted = false;
        syncAudioPlaybackRate(audio, useEditorStore.getState().playbackSpeed);
        void playEditorAudioAt(audio, chartToAudioTime(strikeChartTime, off));
      }
      setIsPlaying(true);
    }
  };

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio || !activeAudioUrl) return;

    const chartTime = useEditorStore.getState().isPlaying
      ? useEditorStore.getState().currentTime
      : beatToTime(
          useEditorStore.getState().scrollTick / RESOLUTION,
          useEditorStore.getState().meta.SongTiming
        );

    const onReady = () => {
      const state = useEditorStore.getState();
      syncAudioPlaybackRate(audio, state.playbackSpeed);
      syncAudioVolume(audio, state.songVolume);
      seekChartTime(chartTime);
      if (state.isPlaying && !isInSilentLeadIn(chartTime, getSongOffset(state.meta))) {
        void playEditorAudioAt(
          audio,
          chartToAudioTime(chartTime, getSongOffset(state.meta))
        );
      }
    };
    audio.addEventListener("loadedmetadata", onReady);
    syncAudioPlaybackRate(audio, playbackSpeed);
    syncAudioVolume(audio, songVolume);
    audio.load();
    return () => audio.removeEventListener("loadedmetadata", onReady);
  }, [activeAudioUrl, audioSource, playbackSpeed, songVolume]);

  useEffect(() => {
    seekChartTime(useEditorStore.getState().currentTime);
  }, [meta.SongOffsetSeconds, meta.SongTiming]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const onEnd = () => setIsPlaying(false);

    audio.addEventListener("ended", onEnd);
    return () => {
      audio.removeEventListener("ended", onEnd);
    };
  }, [setIsPlaying]);

  useEffect(() => {
    if (!isPlaying) {
      cancelAnimationFrame(rafRef.current);
      return;
    }

    const audio = audioRef.current;
    if (!audio) return;

    lastFrameRef.current = performance.now();

    const loop = () => {
      const state = useEditorStore.getState();
      const { currentTime: ct, meta: m, isPlaying: playing } = state;
      const off = getSongOffset(m);
      const dur = getActiveDuration(state);

      if (!playing) return;

      if (ct < off) {
        const now = performance.now();
        const dt = (now - lastFrameRef.current) / 1000;
        lastFrameRef.current = now;
        const speed = state.playbackSpeed;
        const next = ct + dt * speed;
        setCurrentTime(next);

        if (next >= off) {
          audio.muted = false;
          void playEditorAudioAt(audio, 0);
        }
      } else if (!audio.paused && !audio.muted) {
        setCurrentTime(audio.currentTime + off);
      } else if (audio.paused && ct - off < dur) {
        audio.muted = false;
        void playEditorAudioAt(audio, chartToAudioTime(ct, off));
      }

      rafRef.current = requestAnimationFrame(loop);
    };

    rafRef.current = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(rafRef.current);
  }, [isPlaying]);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLSelectElement) return;
      if (e.code === "Space") {
        e.preventDefault();
        togglePlay();
      } else if (e.key === "[") {
        e.preventDefault();
        nudgeOffset(-offsetFromMs(OFFSET_NUDGE_FINE_MS));
      } else if (e.key === "]") {
        e.preventDefault();
        nudgeOffset(offsetFromMs(OFFSET_NUDGE_FINE_MS));
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  });

  const fmt = (t: number) => {
    const m = Math.floor(t / 60);
    const s = Math.floor(t % 60);
    const ms = Math.floor((t % 1) * 100);
    return `${m}:${s.toString().padStart(2, "0")}.${ms.toString().padStart(2, "0")}`;
  };

  const tick = isPlaying ? beatToTick(timeToBeat(chartTime, meta.SongTiming)) : scrollTick;
  const bpm = Math.round(bpmFromAnchors(meta.SongTiming) * 10) / 10;

  return (
    <header className="toolbar">
      <div className="toolbar-left">
        <div className="brand">
          <img className="brand-logo" src="/app-icon.jpg" alt="" aria-hidden />
          <div>
            <h1>Smash Drums Editor</h1>
          </div>
        </div>
        {meta.NameSong && (
          <span className="song-title" title={meta.NameSong}>
            {meta.NameSong}
          </span>
        )}
      </div>

      <div className="toolbar-center">
        <button className="btn play-btn" onClick={togglePlay} disabled={!canPlay} title="Play / Pause (Space)">
          {isPlaying ? (
            <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
              <rect x="6" y="4" width="4" height="16" />
              <rect x="14" y="4" width="4" height="16" />
            </svg>
          ) : (
            <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
              <path d="M8 5v14l11-7z" />
            </svg>
          )}
        </button>
        <div className="btn-group btn-group-tight audio-source-toggle">
          <button
            type="button"
            className={audioSource === "song" ? "btn btn-sm active" : "btn btn-sm"}
            disabled={!audioFileName}
            title={audioFileName ?? "Load song audio"}
            onClick={() => setAudioSource("song")}
          >
            Song
          </button>
          <button
            type="button"
            className={audioSource === "drums" ? "btn btn-sm active" : "btn btn-sm"}
            disabled={!drumsAudioFileName}
            title={drumsAudioFileName ?? "Load drums audio"}
            onClick={() => setAudioSource("drums")}
          >
            Drums
          </button>
        </div>
        <span className="timecode">
          {inSilence
            ? "Silent"
            : `Audio (${playingSource}) ${fmt(audioTime)}`}
        </span>
        <span className="beatcode">
          Chart {fmt(Math.max(0, chartTime))} · {formatTick(tick)}
        </span>
        <button
          className="btn btn-sm"
          type="button"
          title="Jump to song start (beat 0)"
          onClick={() => {
            goToChartStart();
            seekChartTime(0);
          }}
        >
          ⏮ Start
        </button>
        <div
          className="toolbar-bpm"
          title={
            bpmConfidence !== null
              ? `Detect confidence ${Math.round(bpmConfidence * 100)}%`
              : "Song BPM"
          }
        >
          <label className="toolbar-bpm-label">
            <span className="toolbar-bpm-text">BPM</span>
            <input
              className="toolbar-bpm-input"
              type="number"
              min={40}
              max={300}
              step={0.1}
              value={bpm}
              onChange={(e) => setBpm(Number(e.target.value))}
            />
          </label>
          <button
            className="btn btn-sm btn-accent toolbar-bpm-detect"
            type="button"
            disabled={!audioBuffer || bpmDetecting}
            onClick={() => void detectBpmFromAudio()}
          >
            {bpmDetecting ? "…" : "Detect"}
          </button>
        </div>
      </div>

      <div className="toolbar-right">
        <label className="file-btn">
          🎵 Song
          <input
            type="file"
            accept="audio/*,.mp3,.wav,.ogg,.flac,.m4a,.aac"
            hidden
            onChange={(e) => {
              const f = e.target.files?.[0];
              if (f) void loadAudio(f);
            }}
          />
        </label>
        <label className="file-btn">
          🥁 Drums
          <input
            type="file"
            accept="audio/*,.mp3,.wav,.ogg,.flac,.m4a,.aac"
            hidden
            onChange={(e) => {
              const f = e.target.files?.[0];
              if (f) void loadDrumsAudio(f);
            }}
          />
        </label>
        <label
          className="file-btn"
          title="Import .indie / .indies, meta.json, or Clone Hero .chart"
        >
          📂 Import
          <input
            type="file"
            accept=".indie,.indies,.json,.chart,application/json,application/zip"
            hidden
            onChange={(e) => {
              const f = e.target.files?.[0];
              if (f) void loadMeta(f);
              e.target.value = "";
            }}
          />
        </label>
        <button className="btn export-btn" onClick={exportMeta}>
          Export meta.json
        </button>
        <button className="btn" onClick={exportChart}>
          Export CH chart + song.ini
        </button>
      </div>

      <audio id="editor-audio" ref={audioRef} src={activeAudioUrl ?? undefined} />
    </header>
  );
}

import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import App from "./App";

createRoot(document.getElementById("root")!).render(
  <StrictMode>
    <App />
  </StrictMode>
);

import { create } from "zustand";
import type {
  ChartNote,
  Difficulty,
  MetaJson,
  PhasePlacement,
  PlacementMode,
  SongPhase,
  TimingAnchor,
} from "../types/meta";
import {
  clampPhaseId,
  clampPower,
  phaseById,
  sortSongPhases,
} from "../types/meta";

import { validateIndiesCharts } from "../utils/chartNotes";
import { downloadChart, isChartFile, parseChartFile } from "../utils/chartIO";
import { downloadSongIni } from "../utils/songIniIO";
import {
  chartsFromMeta,
  createEmptyMeta,
  downloadMetaJson,
  parseMetaJson,
  prepareMetaForExport,
  withOffsetInTiming,
} from "../utils/metaIO";
import { getSongOffset } from "../utils/offset";
import { parseIndiesFile } from "../utils/indiesIO";
import {
  FIXED_PIXELS_PER_TICK,
  beatToTick,
  beatsEqual,
  clampPixelsPerTick,
  snapBeat,
} from "../utils/resolution";
import {
  clampPlaybackSpeed,
  syncAudioPlaybackRate,
  syncAudioVolume,
} from "../utils/audioPlayback";
import { INDIES_AUDIO_FILE } from "../utils/audioFormat";
import type { AudioSource } from "../utils/audioSource";
import { detectBpm } from "../utils/bpmDetect";
import {
  mergeNotes,
  notesInTickRange,
  parseClipboard,
  pastePayloadAtBeat,
  selectionFirstBeat,
  serializeClipboard,
  type NoteClipboardPayload,
} from "../utils/noteClipboard";

import {
  anchorsFromBpm,
  beatToTime,
  sortTimingAnchors,
  timeToBeat,
} from "../utils/timing";

type EditorState = {
  meta: MetaJson;
  charts: Record<Difficulty, ChartNote[]>;
  difficulty: Difficulty;
  selectedLane: 0 | 1 | 2 | 3 | 4 | 5;
  strength: 0 | 1 | 2;
  snapTicks: number;
  scrollTick: number;
  pixelsPerTick: number;
  /** Vertical wave scale — independent of snap; follows zoom slider only */
  wavePixelsPerTick: number;
  waveScale: number;
  /** Loaded song playback volume (0–1) */
  songVolume: number;
  /** Editor preview volume for strike-bar drum hits (0–1) */
  hitVolume: number;
  /** Preview playback speed — audio + highway scroll (0.25–2) */
  playbackSpeed: number;
  audioUrl: string | null;
  audioFileName: string | null;
  audioFile: File | null;
  audioBuffer: AudioBuffer | null;
  coverImageUrl: string | null;
  coverImageFileName: string | null;
  coverImageFile: File | null;
  drumsAudioUrl: string | null;
  drumsAudioFileName: string | null;
  drumsAudioBuffer: AudioBuffer | null;
  audioSource: AudioSource;
  duration: number;
  currentTime: number;
  isPlaying: boolean;
  bpmDetecting: boolean;
  bpmConfidence: number | null;
  placementMode: PlacementMode;
  pendingPhasePlacement: PhasePlacement;
  noteClipboard: NoteClipboardPayload | null;
  clipboardMessage: string | null;

  setMetaField: <K extends keyof MetaJson>(key: K, value: MetaJson[K]) => void;
  setBpm: (bpm: number) => void;
  detectBpmFromAudio: () => Promise<number | null>;
  setDifficulty: (d: Difficulty) => void;
  setSelectedLane: (lane: 0 | 1 | 2 | 3 | 4 | 5) => void;
  setStrength: (s: 0 | 1 | 2) => void;
  setSnapTicks: (ticks: number) => void;
  setScrollTick: (tick: number) => void;
  setPixelsPerTick: (v: number) => void;
  setWaveScale: (v: number) => void;
  setSongVolume: (v: number) => void;
  setHitVolume: (v: number) => void;
  setPlaybackSpeed: (speed: number) => void;
  setOffset: (seconds: number) => void;
  nudgeOffset: (delta: number) => void;
  setOffsetFromPlayhead: () => void;
  goToChartStart: () => void;
  setCurrentTime: (t: number) => void;
  setIsPlaying: (p: boolean) => void;
  loadAudio: (file: File) => Promise<void>;
  loadDrumsAudio: (file: File) => Promise<void>;
  loadCoverImage: (file: File) => Promise<void>;
  clearCoverImage: () => void;
  setAudioSource: (source: AudioSource) => void;
  loadMeta: (file: File) => Promise<void>;
  loadChart: (file: File) => Promise<void>;
  exportMeta: () => void;
  exportChart: () => void;
  toggleNote: (beat: number, id: 0 | 1 | 2 | 3 | 4 | 5) => void;
  removeNote: (beat: number, id: 0 | 1 | 2 | 3 | 4 | 5) => void;
  getActiveNotes: () => ChartNote[];
  updatePhase: (index: number, patch: Partial<SongPhase>) => void;
  addPhase: () => void;
  addPhaseAtPlayhead: () => void;
  removePhase: (index: number) => void;
  updateAnchor: (index: number, patch: Partial<TimingAnchor>) => void;
  addAnchor: () => void;
  addAnchorAtPlayhead: () => void;
  removeAnchor: (index: number) => void;
  setPlacementMode: (mode: PlacementMode) => void;
  setPendingPhasePlacement: (patch: Partial<PhasePlacement>) => void;
  placePhaseAtBeat: (beat: number) => void;
  placeAnchorAtBeat: (beat: number) => void;
  copyNotesInRange: (minTick: number, maxTick: number) => Promise<number>;
  pasteNotesAtBeat: (strikeBeat: number) => Promise<number>;
  clearClipboardMessage: () => void;
};

const audioContext = new AudioContext();

export const useEditorStore = create<EditorState>((set, get) => ({
  meta: createEmptyMeta(),
  charts: { easy: [], normal: [], hard: [], extreme: [] },
  difficulty: "extreme",
  selectedLane: 1,
  strength: 1,
  snapTicks: 240,
  scrollTick: 0,
  pixelsPerTick: FIXED_PIXELS_PER_TICK,
  wavePixelsPerTick: FIXED_PIXELS_PER_TICK,
  waveScale: 1.4,
  songVolume: 1,
  hitVolume: 0.75,
  playbackSpeed: 1,
  audioUrl: null,
  audioFileName: null,
  audioFile: null,
  audioBuffer: null,
  coverImageUrl: null,
  coverImageFileName: null,
  coverImageFile: null,
  drumsAudioUrl: null,
  drumsAudioFileName: null,
  drumsAudioBuffer: null,
  audioSource: "song",
  duration: 0,
  currentTime: 0,
  isPlaying: false,
  bpmDetecting: false,
  bpmConfidence: null,
  placementMode: null,
  pendingPhasePlacement: {
    phase: 2,
    power: 0.5,
    phaseName: phaseById(2).label,
  },
  noteClipboard: null,
  clipboardMessage: null,

  setMetaField: (key, value) =>
    set((s) => ({ meta: { ...s.meta, [key]: value } })),

  setBpm: (bpm) =>
    set((s) => {
      const offset = getSongOffset(s.meta);
      return {
        meta: {
          ...s.meta,
          SongTiming: withOffsetInTiming(anchorsFromBpm(bpm), offset),
        },
        bpmConfidence: null,
      };
    }),

  detectBpmFromAudio: async () => {
    const { audioBuffer } = get();
    if (!audioBuffer) return null;
    set({ bpmDetecting: true });
    try {
      await new Promise((r) => setTimeout(r, 0));
      const { bpm, confidence } = detectBpm(audioBuffer);
      set((s) => {
        const offset = getSongOffset(s.meta);
        return {
          meta: {
            ...s.meta,
            SongTiming: withOffsetInTiming(anchorsFromBpm(bpm), offset),
          },
          bpmDetecting: false,
          bpmConfidence: confidence,
        };
      });
      return bpm;
    } catch {
      set({ bpmDetecting: false, bpmConfidence: null });
      return null;
    }
  },

  setDifficulty: (difficulty) => set({ difficulty }),
  setSelectedLane: (selectedLane) => set({ selectedLane }),
  setStrength: (strength) => set({ strength }),
  setSnapTicks: (snapTicks) => set({ snapTicks }),
  setScrollTick: (scrollTick) => set({ scrollTick: Math.max(0, scrollTick) }),
  setPixelsPerTick: (pixelsPerTick) => {
    const ppt = clampPixelsPerTick(pixelsPerTick);
    set({ pixelsPerTick: ppt, wavePixelsPerTick: ppt });
  },
  setWaveScale: (waveScale) =>
    set({ waveScale: Math.max(0.25, Math.min(3, waveScale)) }),
  setSongVolume: (songVolume) => {
    const volume = Math.max(0, Math.min(1, songVolume));
    set({ songVolume: volume });
    const audio = document.getElementById("editor-audio") as HTMLAudioElement | null;
    syncAudioVolume(audio, volume);
  },
  setHitVolume: (hitVolume) =>
    set({ hitVolume: Math.max(0, Math.min(1, hitVolume)) }),
  setPlaybackSpeed: (speed) => {
    const playbackSpeed = clampPlaybackSpeed(speed);
    set({ playbackSpeed });
    const audio = document.getElementById("editor-audio") as HTMLAudioElement | null;
    syncAudioPlaybackRate(audio, playbackSpeed);
  },
  setOffset: (seconds) => {
    const offset = Math.round(seconds * 1000) / 1000;
    set((s) => ({
      meta: {
        ...s.meta,
        SongOffsetSeconds: offset,
        SongTiming: withOffsetInTiming(s.meta.SongTiming, offset),
      },
    }));
  },
  nudgeOffset: (deltaSeconds) => {
    const offset =
      Math.round((get().meta.SongOffsetSeconds + deltaSeconds) * 1000) / 1000;
    set((s) => ({
      meta: {
        ...s.meta,
        SongOffsetSeconds: offset,
        SongTiming: withOffsetInTiming(s.meta.SongTiming, offset),
      },
    }));
  },
  setOffsetFromPlayhead: () => {
    const offset = Math.round(get().currentTime * 1000) / 1000;
    set((s) => ({
      meta: {
        ...s.meta,
        SongOffsetSeconds: offset,
        SongTiming: withOffsetInTiming(s.meta.SongTiming, offset),
      },
    }));
  },
  goToChartStart: () => {
    set({ scrollTick: 0, currentTime: 0 });
  },
  setCurrentTime: (currentTime) => set({ currentTime }),
  setIsPlaying: (isPlaying) => set({ isPlaying }),

  loadAudio: async (file) => {
    try {
      if (audioContext.state === "suspended") await audioContext.resume();
      const buf = await file.arrayBuffer();
      const decoded = await audioContext.decodeAudioData(buf.slice(0));
      const prev = get().audioUrl;
      if (prev) URL.revokeObjectURL(prev);
      const url = URL.createObjectURL(file);
      set((s) => ({
        audioUrl: url,
        audioFileName: file.name,
        audioFile: file,
        audioBuffer: decoded,
        duration: decoded.duration,
        scrollTick: 0,
        currentTime: 0,
        isPlaying: false,
        meta: { ...s.meta, FilePath: INDIES_AUDIO_FILE },
      }));
      syncAudioVolume(
        document.getElementById("editor-audio") as HTMLAudioElement | null,
        get().songVolume
      );
    } catch {
      window.alert("Could not decode this audio file. Try OGG, MP3, or WAV.");
    }
  },

  loadDrumsAudio: async (file) => {
    try {
      if (audioContext.state === "suspended") await audioContext.resume();
      const buf = await file.arrayBuffer();
      const decoded = await audioContext.decodeAudioData(buf.slice(0));
      const prev = get().drumsAudioUrl;
      if (prev) URL.revokeObjectURL(prev);
      const url = URL.createObjectURL(file);
      set({
        drumsAudioUrl: url,
        drumsAudioFileName: file.name,
        drumsAudioBuffer: decoded,
      });
    } catch {
      window.alert("Could not decode this drums audio file. Try OGG, MP3, or WAV.");
    }
  },

  setAudioSource: (audioSource) => set({ audioSource }),

  loadCoverImage: async (file) => {
    const prev = get().coverImageUrl;
    if (prev) URL.revokeObjectURL(prev);
    const url = URL.createObjectURL(file);
    set({
      coverImageUrl: url,
      coverImageFileName: file.name,
      coverImageFile: file,
    });
  },

  clearCoverImage: () => {
    const prev = get().coverImageUrl;
    if (prev) URL.revokeObjectURL(prev);
    set({
      coverImageUrl: null,
      coverImageFileName: null,
      coverImageFile: null,
    });
  },

  loadMeta: async (file) => {
    const indiesPackage = await parseIndiesFile(file);
    if (indiesPackage) {
      const { meta, charts, audioFile, coverFile } = indiesPackage;
      set({
        meta,
        charts,
        scrollTick: 0,
        currentTime: 0,
        isPlaying: false,
      });
      if (coverFile) {
        await get().loadCoverImage(coverFile);
      } else {
        get().clearCoverImage();
      }
      if (audioFile) {
        await get().loadAudio(audioFile);
      }
      return;
    }

    const text = await file.text();
    if (isChartFile(text)) {
      const { meta, charts } = parseChartFile(text);
      set({
        meta,
        charts,
        scrollTick: 0,
        currentTime: 0,
        isPlaying: false,
      });
      return;
    }
    const meta = parseMetaJson(text);
    set({
      meta,
      charts: chartsFromMeta(meta),
      scrollTick: 0,
      currentTime: 0,
      isPlaying: false,
    });
  },

  loadChart: async (file) => {
    const text = await file.text();
    const { meta, charts } = parseChartFile(text);
    set({
      meta,
      charts,
      scrollTick: 0,
      currentTime: 0,
      isPlaying: false,
    });
  },

  exportMeta: () => {
    const { meta, charts, audioFileName } = get();
    const issues = validateIndiesCharts(charts);
    if (issues.length > 0) {
      window.alert(issues.join("\n"));
      return;
    }
    const built = prepareMetaForExport(meta, charts);
    if (audioFileName) {
      built.FilePath = INDIES_AUDIO_FILE;
    }
    downloadMetaJson(built, "meta.json");
  },

  exportChart: () => {
    const { meta, charts, audioFileName, duration } = get();
    const issues = validateIndiesCharts(charts);
    if (issues.length > 0) {
      window.alert(issues.join("\n"));
      return;
    }
    const built = prepareMetaForExport(meta, charts);
    downloadChart(built, charts, audioFileName, undefined, duration);
    window.setTimeout(() => {
      downloadSongIni(built, charts, duration);
    }, 300);
  },

  toggleNote: (beat, id) => {
    const { difficulty, strength, charts, snapTicks } = get();
    const snapped = snapBeat(beat, snapTicks);
    const notes = [...charts[difficulty]];
    const cellIdx = notes.findIndex((n) => {
      if (n.Id !== id) return false;
      if (beatToTick(n.Beat) === beatToTick(beat)) return true;
      return beatsEqual(n.Beat, snapped);
    });

    if (cellIdx >= 0) {
      notes.splice(cellIdx, 1);
    } else {
      notes.push({ Beat: snapped, Id: id, Strength: strength });
    }
    notes.sort((a, b) => a.Beat - b.Beat || a.Id - b.Id);
    set({ charts: { ...charts, [difficulty]: notes } });
  },

  removeNote: (beat, id) => {
    const { difficulty, charts } = get();
    const targetTick = beatToTick(beat);
    const notes = charts[difficulty].filter(
      (n) => !(n.Id === id && beatToTick(n.Beat) === targetTick)
    );
    if (notes.length === charts[difficulty].length) return;
    set({ charts: { ...charts, [difficulty]: notes } });
  },

  getActiveNotes: () => get().charts[get().difficulty],

  copyNotesInRange: async (minTick, maxTick) => {
    const { difficulty, charts } = get();
    const picked = notesInTickRange(charts[difficulty], minTick, maxTick);
    if (picked.length === 0) {
      set({ clipboardMessage: "Nothing to copy in view" });
      return 0;
    }
    const anchorBeat = selectionFirstBeat(picked);
    const payload: NoteClipboardPayload = { version: 1, notes: picked, anchorBeat };
    set({ noteClipboard: payload, clipboardMessage: `Copied ${picked.length} notes` });
    try {
      await navigator.clipboard.writeText(serializeClipboard(payload));
    } catch {
      // Internal buffer still works when system clipboard is blocked.
    }
    return picked.length;
  },

  pasteNotesAtBeat: async (strikeBeat) => {
    let payload = get().noteClipboard;
    if (!payload) {
      try {
        const text = await navigator.clipboard.readText();
        payload = parseClipboard(text);
        if (payload) set({ noteClipboard: payload });
      } catch {
        set({ clipboardMessage: "Clipboard empty" });
        return 0;
      }
    }
    if (!payload || payload.notes.length === 0) {
      set({ clipboardMessage: "Clipboard empty" });
      return 0;
    }

    const { difficulty, charts, snapTicks } = get();
    const pasted = pastePayloadAtBeat(payload, strikeBeat, snapTicks);
    const merged = mergeNotes(charts[difficulty], pasted);
    set({
      charts: { ...charts, [difficulty]: merged },
      clipboardMessage: `Pasted ${pasted.length} notes`,
    });
    return pasted.length;
  },

  clearClipboardMessage: () => set({ clipboardMessage: null }),

  updatePhase: (index, patch) =>
    set((s) => {
      const phases = sortSongPhases(s.meta.SongPhases);
      if (index < 0 || index >= phases.length) return s;
      const next = { ...phases[index], ...patch };
      if (patch.phase !== undefined) {
        next.phase = clampPhaseId(patch.phase);
        if (patch.phaseName === undefined) {
          next.phaseName = phaseById(next.phase).label;
        }
      }
      if (patch.power !== undefined) next.power = clampPower(patch.power);
      if (patch.beat !== undefined) next.beat = Math.max(0, patch.beat);
      phases[index] = next;
      return { meta: { ...s.meta, SongPhases: sortSongPhases(phases) } };
    }),

  addPhase: () =>
    set((s) => {
      const phases = sortSongPhases(s.meta.SongPhases);
      const lastBeat = phases.length > 0 ? phases[phases.length - 1].beat : 0;
      const phase: SongPhase = {
        beat: lastBeat + 4,
        phase: 2,
        power: 0.5,
        phaseName: phaseById(2).label,
      };
      return { meta: { ...s.meta, SongPhases: sortSongPhases([...phases, phase]) } };
    }),

  addPhaseAtPlayhead: () =>
    set((s) => {
      const beat = Math.round(timeToBeat(s.currentTime, s.meta.SongTiming) * 1000) / 1000;
      const phase: SongPhase = {
        beat: Math.max(0, beat),
        phase: 2,
        power: 0.5,
        phaseName: phaseById(2).label,
      };
      return {
        meta: {
          ...s.meta,
          SongPhases: sortSongPhases([...s.meta.SongPhases, phase]),
        },
      };
    }),

  removePhase: (index) =>
    set((s) => {
      const phases = sortSongPhases(s.meta.SongPhases);
      if (phases.length <= 1 || index < 0 || index >= phases.length) return s;
      phases.splice(index, 1);
      return { meta: { ...s.meta, SongPhases: phases } };
    }),

  updateAnchor: (index, patch) =>
    set((s) => {
      const anchors = sortTimingAnchors(s.meta.SongTiming);
      if (index < 0 || index >= anchors.length) return s;
      const next = { ...anchors[index], ...patch };
      if (patch.beat !== undefined) next.beat = Math.max(0, patch.beat);
      if (patch.timer !== undefined) next.timer = Math.max(0, patch.timer);
      anchors[index] = next;
      const timing = sortTimingAnchors(anchors);
      const offset =
        timing[0]?.beat === 0 ? timing[0].timer : s.meta.SongOffsetSeconds;
      return {
        meta: {
          ...s.meta,
          SongOffsetSeconds: offset,
          SongTiming: timing,
        },
      };
    }),

  addAnchor: () =>
    set((s) => {
      const anchors = sortTimingAnchors(s.meta.SongTiming);
      const last = anchors[anchors.length - 1];
      const beat = last.beat + 4;
      const anchor: TimingAnchor = { beat, timer: beatToTime(beat, anchors) };
      return { meta: { ...s.meta, SongTiming: sortTimingAnchors([...anchors, anchor]) } };
    }),

  addAnchorAtPlayhead: () =>
    set((s) => {
      const beat = Math.round(timeToBeat(s.currentTime, s.meta.SongTiming) * 1000) / 1000;
      const timer = Math.round(s.currentTime * 1000) / 1000;
      const anchor: TimingAnchor = { beat: Math.max(0, beat), timer: Math.max(0, timer) };
      const anchors = sortTimingAnchors([...s.meta.SongTiming, anchor]);
      const deduped = anchors.filter(
        (item, idx, list) =>
          idx === 0 ||
          Math.abs(item.beat - list[idx - 1].beat) > 1 / 480 ||
          Math.abs(item.timer - list[idx - 1].timer) > 0.001
      );
      return { meta: { ...s.meta, SongTiming: deduped.length >= 2 ? deduped : anchors } };
    }),

  removeAnchor: (index) =>
    set((s) => {
      const anchors = sortTimingAnchors(s.meta.SongTiming);
      if (anchors.length <= 2 || index < 0 || index >= anchors.length) return s;
      anchors.splice(index, 1);
      return { meta: { ...s.meta, SongTiming: anchors } };
    }),

  setPlacementMode: (placementMode) => set({ placementMode }),

  setPendingPhasePlacement: (patch) =>
    set((s) => {
      const next: PhasePlacement = { ...s.pendingPhasePlacement, ...patch };
      if (patch.phase !== undefined) {
        next.phase = clampPhaseId(patch.phase);
        if (patch.phaseName === undefined) {
          next.phaseName = phaseById(next.phase).label;
        }
      }
      if (patch.power !== undefined) next.power = clampPower(patch.power);
      if (patch.phaseName !== undefined) next.phaseName = patch.phaseName.trim() || phaseById(next.phase).label;
      return { pendingPhasePlacement: next };
    }),

  placePhaseAtBeat: (beat) =>
    set((s) => {
      const snapped = snapBeat(Math.max(0, beat), s.snapTicks);
      const phases = sortSongPhases(s.meta.SongPhases);
      const existing = phases.findIndex((ph) => beatsEqual(ph.beat, snapped));
      const template = s.pendingPhasePlacement;
      const nextPhase: SongPhase = {
        beat: snapped,
        phase: clampPhaseId(template.phase),
        power: clampPower(template.power),
        phaseName: template.phaseName.trim() || phaseById(template.phase).label,
      };
      if (existing >= 0) phases[existing] = nextPhase;
      else phases.push(nextPhase);
      return { meta: { ...s.meta, SongPhases: sortSongPhases(phases) } };
    }),

  placeAnchorAtBeat: (beat) =>
    set((s) => {
      const snapped = snapBeat(Math.max(0, beat), s.snapTicks);
      const anchors = sortTimingAnchors(s.meta.SongTiming);
      const timer = Math.round(beatToTime(snapped, anchors) * 1000) / 1000;
      const existing = anchors.findIndex((a) => beatsEqual(a.beat, snapped));
      const next: TimingAnchor = { beat: snapped, timer };
      if (existing >= 0) anchors[existing] = next;
      else anchors.push(next);
      const deduped = sortTimingAnchors(anchors).filter(
        (item, idx, list) =>
          idx === 0 ||
          Math.abs(item.beat - list[idx - 1].beat) > 1 / 480 ||
          Math.abs(item.timer - list[idx - 1].timer) > 0.001
      );
      return {
        meta: {
          ...s.meta,
          SongTiming: deduped.length >= 2 ? deduped : sortTimingAnchors(anchors),
        },
      };
    }),
}));

/* SmashDrumsEditor — NEXUS future theme */

@import url("https://fonts.googleapis.com/css2?family=Orbitron:wght@500;600;700;800&family=Rajdhani:wght@400;500;600;700&family=Share+Tech+Mono&display=swap");

.app--future {
  --bg: #000000;
  --bg-elevated: #000000;
  --bg-panel: #000000;
  --border: rgba(255, 184, 0, 0.14);
  --border-hover: rgba(232, 38, 42, 0.4);
  --text: #fff8ee;
  --text-muted: #9a8a78;
  --accent: #ffb800;
  --accent-2: #e8262a;
  --accent-3: #ff6b1a;
  --accent-glow: rgba(255, 184, 0, 0.35);
  --accent-glow-2: rgba(232, 38, 42, 0.3);
  --radius: 4px;
  --radius-sm: 2px;
  --font-display: "Orbitron", system-ui, sans-serif;
  --font-ui: "Rajdhani", system-ui, sans-serif;
  --font-mono: "Share Tech Mono", "JetBrains Mono", monospace;
  font-family: var(--font-ui);
  position: relative;
  isolation: isolate;
}

.app--future .ambient {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  overflow: hidden;
}

.app--future .ambient__grid {
  position: absolute;
  inset: -40% -20%;
  background-image:
    linear-gradient(rgba(255, 184, 0, 0.04) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 184, 0, 0.04) 1px, transparent 1px);
  background-size: 48px 48px;
  transform: perspective(600px) rotateX(58deg) translateY(-8%);
  transform-origin: 50% 0%;
  animation: grid-drift 24s linear infinite;
  mask-image: radial-gradient(ellipse 90% 70% at 50% 40%, black 20%, transparent 75%);
}

.app--future .ambient__orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(80px);
  opacity: 0.45;
  animation: orb-float 12s ease-in-out infinite;
}

.app--future .ambient__orb--a {
  width: 420px;
  height: 420px;
  top: -120px;
  left: 12%;
  background: radial-gradient(circle, rgba(232, 38, 42, 0.5), transparent 70%);
}

.app--future .ambient__orb--b {
  width: 520px;
  height: 520px;
  bottom: -180px;
  right: 8%;
  background: radial-gradient(circle, rgba(255, 184, 0, 0.35), transparent 70%);
  animation-delay: -4s;
}

.app--future .ambient__orb--c {
  width: 280px;
  height: 280px;
  top: 40%;
  left: 45%;
  background: radial-gradient(circle, rgba(255, 107, 26, 0.4), transparent 70%);
  animation-delay: -7s;
}

.app--future .ambient__scanlines {
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    0deg,
    transparent,
    transparent 2px,
    rgba(0, 0, 0, 0.12) 2px,
    rgba(0, 0, 0, 0.12) 4px
  );
  opacity: 0.35;
  mix-blend-mode: overlay;
}

.app--future .app-shell {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 0;
}

@keyframes grid-drift {
  from {
    background-position: 0 0, 0 0;
  }
  to {
    background-position: 0 96px, 96px 0;
  }
}

@keyframes orb-float {
  0%,
  100% {
    transform: translate(0, 0) scale(1);
  }
  50% {
    transform: translate(24px, -18px) scale(1.06);
  }
}

@keyframes neon-pulse {
  0%,
  100% {
    box-shadow:
      0 0 12px var(--accent-glow),
      inset 0 0 20px rgba(255, 184, 0, 0.06);
  }
  50% {
    box-shadow:
      0 0 28px var(--accent-glow),
      0 0 48px var(--accent-glow-2),
      inset 0 0 28px rgba(232, 38, 42, 0.08);
  }
}

@keyframes border-flow {
  0% {
    background-position: 0% 50%;
  }
  100% {
    background-position: 200% 50%;
  }
}

/* Toolbar */
.app--future .toolbar {
