}

.app--future .export-btn {
  clip-path: polygon(8px 0, 100% 0, calc(100% - 8px) 100%, 0 100%);
  background: linear-gradient(90deg, var(--accent-3), var(--accent));
}

/* Sidebars + HUD panels */
.app--future .sidebar {
  background: rgba(0, 0, 0, 0.94);
  border-color: rgba(255, 184, 0, 0.1);
  backdrop-filter: blur(16px);
}

.app--future .sidebar-left {
  border-right: 1px solid rgba(232, 38, 42, 0.15);
  box-shadow: inset -1px 0 0 rgba(255, 184, 0, 0.08);
}

.app--future .sidebar-right {
  border-left: 1px solid rgba(255, 184, 0, 0.15);
  box-shadow: inset 1px 0 0 rgba(232, 38, 42, 0.08);
}

.app--future .hud-panel {
