}

.app--future .collapsible-badge {
  color: var(--accent-2);
  border-color: rgba(232, 38, 42, 0.35);
  background: rgba(232, 38, 42, 0.1);
  border-radius: 2px;
  clip-path: polygon(6px 0, 100% 0, calc(100% - 6px) 100%, 0 100%);
}

.app--future .panel input,
.app--future .panel select {
  background: #000000 !important;
  color: #fff8ee !important;
  -webkit-text-fill-color: #fff8ee;
  color-scheme: dark;
}

.app--future .toolbar-bpm-input {
  background: #000000 !important;
  color: #fff8ee !important;
  -webkit-text-fill-color: #fff8ee !important;
  caret-color: var(--accent);
