}

.app--future .btn.active,
.app--future .btn.is-active {
  background: rgba(255, 184, 0, 0.1);
  border-color: var(--accent);
  color: var(--accent);
  box-shadow: 0 0 14px rgba(255, 184, 0, 0.2);
}

.app--future .btn-accent {
  border-color: rgba(255, 179, 71, 0.45);
