  background: rgba(255, 179, 71, 0.08);
}

/* Highway frame */
.app--future .chart-wrap {
  border: 1px solid transparent;
  border-radius: 2px;
  background:
    linear-gradient(var(--bg), var(--bg)) padding-box,
    linear-gradient(
        120deg,
        rgba(255, 184, 0, 0.5),
        rgba(232, 38, 42, 0.35),
        rgba(255, 107, 26, 0.4),
        rgba(255, 184, 0, 0.5)
      )
