@import url("https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap");

:root {
  color-scheme: dark;
  font-family: "Inter", system-ui, sans-serif;
  --bg: #000000;
  --bg-elevated: #000000;
  --bg-panel: #000000;
  --border: rgba(255, 255, 255, 0.07);
  --border-hover: rgba(255, 255, 255, 0.14);
  --text: #f0f0f5;
  --text-muted: #8888a0;
  --accent: #ffb800;
  --accent-2: #e8262a;
  --accent-glow: rgba(255, 184, 0, 0.28);
  --radius: 10px;
  --radius-sm: 6px;
  /* Panels at 3/4 of the 496px width */
  --sidebar-width: 372px;
  /* Blank space between panels and highway */
  --panel-highway-gap: 36px;
  /* Highway width when 496px panels sat flush — keeps chart size unchanged */
  --highway-slot-width: max(360px, calc(100vw - 992px));
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  height: 100%;
  width: 100%;
}

body {
  margin: 0;
  overflow: hidden;
  background: var(--bg);
  color: var(--text);
}

.app {
  display: flex;
  flex-direction: column;
  height: 100%;
  width: 100%;
  min-height: 0;
  background: var(--bg);
}

/* ── Toolbar ── */
.toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 10px 16px;
  padding: 10px 16px;
  background: rgba(0, 0, 0, 0.94);
  backdrop-filter: blur(16px);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.toolbar-left {
  display: flex;
  align-items: center;
  gap: 14px;
  min-width: 0;
  flex: 1 1 180px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.brand-icon {
  width: 32px;
  height: 32px;
  border-radius: 8px;
  background: linear-gradient(135deg, var(--accent-2), var(--accent));
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  box-shadow: 0 0 20px var(--accent-glow);
}

.brand-logo {
  width: 36px;
  height: 36px;
  border-radius: 6px;
  object-fit: cover;
  flex-shrink: 0;
}

.cover-preview {
  display: block;
  width: 100%;
  max-width: 180px;
  aspect-ratio: 1;
  object-fit: cover;
  border-radius: var(--radius-sm);
  border: 1px solid var(--border);
  margin-bottom: 6px;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.35);
}

.cover-actions {
  margin-top: 2px;
}

.cover-btn {
  flex: 1;
  text-align: center;
  cursor: pointer;
}

.toolbar-left h1 {
  margin: 0;
  font-size: 1rem;
  font-weight: 700;
  background: linear-gradient(135deg, #fff 30%, var(--accent));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.song-title {
  font-size: 0.82rem;
  color: var(--text-muted);
  padding: 3px 10px;
  background: rgba(255, 255, 255, 0.04);
  border-radius: 20px;
  border: 1px solid var(--border);
  min-width: 0;
  max-width: min(200px, 100%);
  flex: 0 1 auto;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.toolbar-center {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 10px;
  padding: 6px 14px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid var(--border);
  border-radius: 40px;
  flex: 0 1 auto;
}

.toolbar-right {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
  flex: 1 1 280px;
  justify-content: flex-end;
}

.timecode {
  font-family: "JetBrains Mono", monospace;
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text);
}

.beatcode {
  font-family: "JetBrains Mono", monospace;
  font-size: 0.75rem;
  color: var(--text-muted);
  padding-left: 12px;
  border-left: 1px solid var(--border);
}

.toolbar-bpm {
  display: flex;
  align-items: center;
  gap: 6px;
  padding-left: 12px;
  border-left: 1px solid var(--border);
}

.toolbar-bpm-label {
  display: flex;
  align-items: center;
  gap: 6px;
  margin: 0;
}

.toolbar-bpm-text {
  font-size: 0.65rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-muted);
}

.toolbar-bpm-input {
  width: 68px;
  background: #000000;
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  -webkit-text-fill-color: currentColor;
  caret-color: var(--accent);
  padding: 4px 6px;
  font-size: 0.78rem;
  font-family: "JetBrains Mono", monospace;
  outline: none;
  color-scheme: dark;
}

.toolbar-bpm-input:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 2px var(--accent-glow);
}

.toolbar-bpm-detect {
  white-space: nowrap;
}

/* ── Workspace ── */
.workspace {
  display: flex;
  flex: 1;
  min-height: 0;
  min-width: 0;
  align-items: stretch;
  overflow: hidden;
}

.sidebar-wing {
  flex: 1 1 0;
  min-width: 0;
  display: flex;
  justify-content: center;
  align-items: stretch;
  padding: 0 var(--panel-highway-gap);
}

.editor-main {
  flex: 0 0 var(--highway-slot-width);
  width: var(--highway-slot-width);
  max-width: var(--highway-slot-width);
  display: flex;
  flex-direction: column;
  align-items: stretch;
  min-width: 0;
  min-height: 0;
  padding: 6px 8px;
}

/* ── Chart / Highway ── */
.chart-stage {
  flex: 1;
  display: flex;
  flex-direction: row;
  align-items: stretch;
  width: 100%;
  min-height: 0;
  min-width: 0;
  gap: 0;
}

.chart-wrap {
  flex: 1;
  width: 100%;
  min-height: 0;
  position: relative;
  border-radius: var(--radius);
  overflow: hidden;
  border: 1px solid rgba(255, 184, 0, 0.2);
  box-shadow:
    0 0 40px rgba(255, 184, 0, 0.06),
    0 8px 32px rgba(0, 0, 0, 0.55),
    inset 0 1px 0 rgba(255, 184, 0, 0.08);
}

.chart-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
  cursor: crosshair;
}

.song-overview {
  width: 148px;
  flex-shrink: 0;
  position: relative;
  border-left: 1px solid rgba(255, 184, 0, 0.22);
  background: #000000;
  cursor: ns-resize;
  user-select: none;
  touch-action: none;
  box-shadow: inset 8px 0 24px rgba(255, 184, 0, 0.04);
}

.song-overview:hover {
  border-left-color: rgba(255, 184, 0, 0.38);
  box-shadow:
    inset 8px 0 28px rgba(255, 184, 0, 0.07),
    -4px 0 20px rgba(255, 184, 0, 0.06);
}

.song-overview.is-scrubbing {
  cursor: grabbing;
  border-left-color: rgba(255, 184, 0, 0.55);
}

.song-overview-canvas {
