export type BpmResult = {
  bpm: number;
  confidence: number;
};

/**
 * Estimate BPM from an AudioBuffer using spectral flux + autocorrelation.
 * Analyzes up to 90 seconds of audio.
 */
export function detectBpm(buffer: AudioBuffer): BpmResult {
  const sampleRate = buffer.sampleRate;
  const channel = buffer.getChannelData(0);
  const maxLen = Math.min(channel.length, Math.floor(sampleRate * 90));

  const fps = 100;
  const frameSize = Math.floor(sampleRate / fps);
  const frames = Math.floor(maxLen / frameSize);
  if (frames < fps * 4) return { bpm: 120, confidence: 0 };

  const envelope = new Float32Array(frames);
  for (let f = 0; f < frames; f++) {
    let e = 0;
    const start = f * frameSize;
    for (let i = 0; i < frameSize; i++) {
      const v = channel[start + i] ?? 0;
      e += v * v;
    }
    envelope[f] = Math.sqrt(e / frameSize);
  }

  const flux = new Float32Array(frames);
  for (let f = 1; f < frames; f++) {
    flux[f] = Math.max(0, envelope[f] - envelope[f - 1]);
  }

  const minBpm = 55;
  const maxBpm = 220;
  const minLag = Math.max(2, Math.floor((fps * 60) / maxBpm));
  const maxLag = Math.floor((fps * 60) / minBpm);

  const scores: { lag: number; score: number }[] = [];
  for (let lag = minLag; lag <= maxLag; lag++) {
    let corr = 0;
    let n = 0;
    for (let f = 0; f < frames - lag; f++) {
      corr += flux[f] * flux[f + lag];
      n++;
    }
    scores.push({ lag, score: n > 0 ? corr / n : 0 });
  }

  scores.sort((a, b) => b.score - a.score);
  const best = scores[0];
  if (!best || best.score <= 0) return { bpm: 120, confidence: 0 };

  let bpm = (60 * fps) / best.lag;

  // Resolve half/double tempo ambiguities using top candidates
  const candidates = new Set<number>();
  for (const { lag } of scores.slice(0, 8)) {
    let b = (60 * fps) / lag;
    while (b < 75) b *= 2;
    while (b > 190) b /= 2;
    candidates.add(Math.round(b * 10) / 10);
  }

  const ranked = [...candidates].map((b) => {
    const targetLag = (60 * fps) / b;
    let score = 0;
    for (const { lag, score: s } of scores) {
      const ratio = lag / targetLag;
      const harm = Math.min(Math.abs(ratio - 1), Math.abs(ratio - 2), Math.abs(ratio - 0.5));
      if (harm < 0.08) score = Math.max(score, s);
    }
    return { bpm: b, score };
  });
  ranked.sort((a, b) => b.score - a.score);

  const pick = ranked[0] ?? { bpm, score: best.score };
  const maxScore = scores[0].score;
  const confidence = maxScore > 0 ? Math.min(1, pick.score / maxScore) : 0;

  return {
    bpm: Math.round(pick.bpm * 10) / 10,
    confidence: Math.round(confidence * 100) / 100,
  };
}

import type { ChartNote, Difficulty, MetaJson, SongPhase, TimingAnchor } from "../types/meta";
import { clampPhaseId, clampPower, phaseById } from "../types/meta";
import { RESOLUTION } from "./resolution";
import { normalizeChartNotes } from "./chartNotes";
import { chDrumEntriesToNotes, indiesNoteToChLanes } from "./chartLaneMapping";
import { CHART_MUSIC_STREAM } from "./audioFormat";
import { getSongOffset } from "./offset";
import { buildMetaJson, createEmptyMeta, withOffsetInTiming } from "./metaIO";
import {
  anchorsFromBpm,
  beatToTime,
  bpmAtAnchor,
  bpmFromAnchors,
  maxContentBeat,
  sortTimingAnchors,
  timeToBeat,
} from "./timing";

const CHART_DIFFICULTY_SECTIONS: Record<Difficulty, string> = {
  easy: "EasyDrums",
  normal: "MediumDrums",
  hard: "HardDrums",
  extreme: "ExpertDrums",
};

const SECTION_TO_DIFFICULTY: Record<string, Difficulty> = {
  EasyDrums: "easy",
  MediumDrums: "normal",
  HardDrums: "hard",
  ExpertDrums: "extreme",
};

/** Moonscraper [Song] Difficulty field (ExpertDrums section still holds the notes). */
const CHART_DIFFICULTY = 0;

type TrackEntry = { tick: number; key: string; value: string };

function escapeChartString(value: string): string {
  return value.replace(/\\/g, "\\\\").replace(/"/g, '\\"');
}

function unescapeChartString(value: string): string {
  return value.replace(/\\"/g, '"').replace(/\\\\/g, "\\");
}

function parseQuotedValue(raw: string): string {
  const trimmed = raw.trim();
  if (trimmed.startsWith('"') && trimmed.endsWith('"')) {
    return unescapeChartString(trimmed.slice(1, -1));
  }
  return trimmed;
}

function bpmAtBeat(beat: number, anchors: TimingAnchor[]): number {
  const sorted = sortTimingAnchors(anchors);
  if (sorted.length < 2) return bpmFromAnchors(sorted);

  for (let i = 0; i < sorted.length - 1; i++) {
    const a = sorted[i];
    const b = sorted[i + 1];
    if (beat >= a.beat && beat <= b.beat) return bpmAtAnchor(sorted, i);
  }

  return bpmAtAnchor(sorted, sorted.length - 2);
}

/** Tempo-change anchors only — not the closing duration anchor. */
function tempoChangeAnchors(anchors: TimingAnchor[], toleranceBpm = 0.1): TimingAnchor[] {
  const sorted = sortTimingAnchors(anchors);
  if (sorted.length === 0) return anchorsFromBpm(120);

  const result: TimingAnchor[] = [sorted[0]];
  let lastBpm = bpmAtAnchor(sorted, 0);

  for (let i = 1; i < sorted.length; i++) {
    const bpm = bpmAtAnchor(sorted, i);
    if (Math.abs(bpm - lastBpm) > toleranceBpm) {
      result.push(sorted[i]);
      lastBpm = bpm;
    }
  }

  return result;
}

function syncEndBeat(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>,
  duration: number
): number {
  let endBeat = maxContentBeat(meta, charts);

  if (duration > 0) {
    const audioEndBeat = timeToBeat(
      duration + getSongOffset(meta),
      meta.SongTiming
    );
    endBeat = Math.max(endBeat, audioEndBeat);
  }

  return Math.max(endBeat, 4);
}

/**
 * Clone Hero [SyncTrack] — start anchor, optional tempo changes (each with TS 4),
 * closing anchor at song end with TS 4 + A + B (see TCBAITW notes.chart).
 */
function buildSyncTrackLines(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>,
  duration: number
): string[] {
  const anchors = sortTimingAnchors(meta.SongTiming);
  const changes = tempoChangeAnchors(anchors);
  const lines: string[] = [];

  const startBpm = Math.round(bpmAtAnchor(anchors, 0) * 1000);
  lines.push("  0 = TS 4");
  lines.push("  0 = A 0");
  lines.push(`  0 = B ${startBpm}`);

  for (let i = 1; i < changes.length; i++) {
    const anchor = changes[i];
    const tick = Math.round(anchor.beat * RESOLUTION);
    if (tick <= 0) continue;

    const micros = Math.round(anchor.timer * 1_000_000);
    const bpm = Math.round(bpmAtBeat(anchor.beat, anchors) * 1000);
    lines.push(`  ${tick} = TS 4`);
    lines.push(`  ${tick} = A ${micros}`);
    lines.push(`  ${tick} = B ${bpm}`);
  }

  const endBeat = syncEndBeat(meta, charts, duration);
  const endTick = Math.round(endBeat * RESOLUTION);
  const endMicros = Math.round(beatToTime(endBeat, anchors) * 1_000_000);
  const endBpm = Math.round(bpmAtBeat(endBeat, anchors) * 1000);

  const lastChangeTick =
    changes.length > 0 ? Math.round(changes[changes.length - 1].beat * RESOLUTION) : 0;

  if (endTick > lastChangeTick) {
    lines.push(`  ${endTick} = TS 4`);
    lines.push(`  ${endTick} = A ${endMicros}`);
    lines.push(`  ${endTick} = B ${endBpm}`);
  }

  return lines;
}

function formatEventLabel(phaseName: string): string {
  const trimmed = phaseName.trim();
  if (!trimmed) return "section Intro";
  if (/^section\s+/i.test(trimmed)) return trimmed;
  return `section ${trimmed}`;
}

function buildEventLines(meta: MetaJson): string[] {
  return [...meta.SongPhases]
    .sort((a, b) => a.beat - b.beat)
    .map((phase) => {
      const tick = Math.round(phase.beat * RESOLUTION);
      const label = escapeChartString(formatEventLabel(phase.phaseName));
      return `  ${tick} = E "${label}"`;
    });
}

function buildDrumLines(notes: ChartNote[]): string[] {
  const lanesByTick = new Map<number, number[]>();

  for (const note of normalizeChartNotes(notes)) {
    const tick = Math.round(note.Beat * RESOLUTION);
    const chLanes = indiesNoteToChLanes(note);
    if (chLanes.length === 0) continue;

    const existing = lanesByTick.get(tick) ?? [];
    existing.push(...chLanes);
    lanesByTick.set(tick, existing);
  }

  const lines: string[] = [];
  for (const tick of [...lanesByTick.keys()].sort((a, b) => a - b)) {
    const uniqueLanes = [...new Set(lanesByTick.get(tick)!)].sort((a, b) => a - b);
    for (const lane of uniqueLanes) {
      lines.push(`  ${tick} = N ${lane} 0`);
    }
  }

  return lines;
}

function musicStreamName(_meta: MetaJson, audioFileName: string | null): string {
  if (audioFileName?.trim()) return CHART_MUSIC_STREAM;
  return CHART_MUSIC_STREAM;
}

function chartSection(name: string, lines: string[]): string {
  const body = lines.length > 0 ? `${lines.join("\n")}\n` : "";
  return `[${name}]\n{\n${body}}`;
}

export function buildChartText(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>,
  audioFileName: string | null = null,
  duration = 0
): string {
  const built = buildMetaJson(meta, charts);
  const offsetMs = Math.round(built.SongOffsetSeconds * 1000);
  const musicStream = escapeChartString(musicStreamName(built, audioFileName));

  const sections: string[] = [
    chartSection("Song", [
      `  Name = "${escapeChartString(built.NameSong)}"`,
      `  Artist = "${escapeChartString(built.NameArtist)}"`,
      `  Charter = "${escapeChartString(built.NameCharter)}"`,
      `  Offset = ${offsetMs}`,
      `  Resolution = ${RESOLUTION}`,
      `  Player2 = bass`,
      `  Difficulty = ${CHART_DIFFICULTY}`,
      `  PreviewStart = 0`,
      `  PreviewEnd = 0`,
      `  Genre = "rock"`,
      `  MediaType = "cd"`,
      `  MusicStream = "${musicStream}"`,
    ]),
    chartSection("SyncTrack", buildSyncTrackLines(built, charts, duration)),
    chartSection("Events", buildEventLines(built)),
  ];

  const drumOrder: Difficulty[] = ["extreme", "hard", "normal", "easy"];
  for (const diff of drumOrder) {
    const notes = charts[diff];
    if (notes.length > 0) {
      sections.push(chartSection(CHART_DIFFICULTY_SECTIONS[diff], buildDrumLines(notes)));
    }
  }

  return `\uFEFF${sections.join("\n")}\n`;
}

export function chartFilename(_songName?: string): string {
  return "notes.chart";
}

export function downloadChart(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>,
  audioFileName: string | null = null,
  filename?: string,
  duration = 0
): void {
  const built = buildMetaJson(meta, charts);
  const name = filename ?? chartFilename();
  const blob = new Blob([buildChartText(built, charts, audioFileName, duration)], {
    type: "text/plain;charset=utf-8",
  });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = name;
  link.click();
  URL.revokeObjectURL(url);
}

function parseChartSections(text: string): {
  song: Record<string, string>;
  tracks: Map<string, TrackEntry[]>;
} {
  const song: Record<string, string> = {};
  const tracks = new Map<string, TrackEntry[]>();
  const clean = text.replace(/^\uFEFF/, "");

  let currentSection = "";
  let inBlock = false;

  for (const rawLine of clean.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith("//")) continue;

    const sectionMatch = line.match(/^\[([^\]]+)\]$/);
    if (sectionMatch) {
      currentSection = sectionMatch[1];
      if (currentSection !== "Song") {
        tracks.set(currentSection, []);
      }
      inBlock = false;
      continue;
    }

    if (line === "{") {
      inBlock = true;
      continue;
    }
    if (line === "}") {
      inBlock = false;
      continue;
    }
    if (!inBlock || !currentSection) continue;

    if (currentSection === "Song") {
      const songMatch = line.match(/^(\w+)\s*=\s*(.+)$/);
      if (songMatch) {
        song[songMatch[1]] = parseQuotedValue(songMatch[2]);
      }
      continue;
    }

    const trackMatch = line.match(/^(\d+)\s*=\s*(\w+)(?:\s+(.+))?$/);
    if (trackMatch) {
      const tick = Number(trackMatch[1]);
      const key = trackMatch[2];
      const value = trackMatch[3] ? parseQuotedValue(trackMatch[3]) : "";
      tracks.get(currentSection)?.push({ tick, key, value });
    }
  }

  return { song, tracks };
}

function syncTrackToAnchors(entries: TrackEntry[]): TimingAnchor[] {
  const aByTick = new Map<number, number>();
  const bByTick = new Map<number, number>();

  for (const entry of entries) {
    if (entry.key === "A") aByTick.set(entry.tick, Number(entry.value));
    if (entry.key === "B") bByTick.set(entry.tick, Number(entry.value));
  }

  const aTicks = [...aByTick.keys()].sort((a, b) => a - b);

  if (aTicks.length >= 2) {
    return aTicks.map((tick) => ({
      beat: tick / RESOLUTION,
      timer: (aByTick.get(tick) ?? 0) / 1_000_000,
    }));
  }

  const bpm = (bByTick.get(0) ?? 120000) / 1000;
  if (aTicks.length === 1 && aTicks[0] === 0) {
    const endTick = Math.max(...entries.map((e) => e.tick), 0);
    const endBeat = endTick / RESOLUTION;
    const endMicros = aByTick.get(endTick);
    if (endMicros !== undefined && endBeat > 0) {
      return [
        { beat: 0, timer: 0 },
        { beat: endBeat, timer: endMicros / 1_000_000 },
      ];
    }
  }

  return anchorsFromBpm(bpm);
}

function eventsToPhases(entries: TrackEntry[]): SongPhase[] {
  const phases = entries
    .filter((entry) => entry.key === "E")
    .sort((a, b) => a.tick - b.tick)
    .map((entry) => {
      const rawName = entry.value.trim();
      return {
        beat: entry.tick / RESOLUTION,
        phase: 1 as const,
        power: 1,
        phaseName: rawName,
      };
    });

  return phases.length > 0
    ? phases
    : [{ beat: 0, phase: 1, power: 1, phaseName: "section Intro" }];
}

function drumEntriesToNotes(entries: TrackEntry[]): ChartNote[] {
  const drumEntries = entries
    .filter((entry) => entry.key === "N")
    .map((entry) => {
      const lane = Number(entry.value.split(/\s+/)[0]);
      return { tick: entry.tick, lane };
    })
    .filter((entry) => Number.isFinite(entry.lane));

  return normalizeChartNotes(chDrumEntriesToNotes(drumEntries, RESOLUTION));
}

export function parseChartFile(raw: string): { meta: MetaJson; charts: Record<Difficulty, ChartNote[]> } {
  const base = createEmptyMeta();
  const { song, tracks } = parseChartSections(raw);

  const charts: Record<Difficulty, ChartNote[]> = {
    easy: [],
    normal: [],
    hard: [],
    extreme: [],
  };

  for (const [section, entries] of tracks) {
    const difficulty = SECTION_TO_DIFFICULTY[section];
    if (difficulty) charts[difficulty] = drumEntriesToNotes(entries);
  }

  const syncEntries = tracks.get("SyncTrack") ?? [];
  const eventEntries = tracks.get("Events") ?? [];
  const offsetMs = Number(song.Offset ?? 0);
  const chartOffset = offsetMs / 1000;
  const rawTiming = syncTrackToAnchors(syncEntries);
  const songOffset = getSongOffset({
    SongOffsetSeconds: chartOffset,
    SongTiming: rawTiming,
  });

  const meta: MetaJson = {
    ...base,
    NameSong: song.Name ?? base.NameSong,
    NameArtist: song.Artist ?? base.NameArtist,
    NameCharter: song.Charter ?? base.NameCharter,
    FilePath: song.MusicStream ?? "",
    SongOffsetSeconds: songOffset,
    SongTiming: withOffsetInTiming(rawTiming, songOffset),
    SongPhases: eventsToPhases(eventEntries).map((phase) => ({
      beat: phase.beat,
      phase: clampPhaseId(phase.phase),
      power: clampPower(phase.power),
      phaseName: phase.phaseName?.trim() || phaseById(phase.phase).label,
    })),
    ChartEasy: charts.easy,
    ChartNormal: charts.normal,
    ChartHard: charts.hard,
    ChartExtreme: charts.extreme,
  };

  return { meta, charts };
}

export function isChartFile(text: string): boolean {
  return /^\uFEFF?\[Song\]/m.test(text);
}

import type { ChartNote } from "../types/meta";
import { CH_CYMBAL_OFFSET, DRUM_LANES } from "../types/meta";
import { clampDrumId } from "./chartNotes";

/** Matches ChartDrumsParser.DrumInstrument base lanes 0–4. */
export const CH_BASE_LANES = [0, 1, 2, 3, 4] as const;

export const CH_STRONG_OFFSET = 33;
export const CH_LIGHT_OFFSET = 39;

/**
 * ChartDrumsParser.GetInstrument — CH pad + cymbal flag → Indies meta Id.
 * Lane 2 + cymbal → HiHat (4); lanes 3/4 + cymbal → Cymbal (2); pads 2–4 → Tom (3).
 */
export function getInstrumentId(baseLane: number, isCymbal: boolean): ChartNote["Id"] {
  switch (baseLane) {
    case 0:
      return 0;
    case 1:
      return 1;
    case 2:
      return isCymbal ? 4 : 3;
    case 3:
    case 4:
      return isCymbal ? 2 : 3;
    default:
      return clampDrumId(baseLane);
  }
}

export type ChDrumTickEntry = { tick: number; lane: number };

/** Parse one difficulty section the same way as ChartDrumsParser.ParseOneDifficulty. */
export function chDrumEntriesToNotes(
  entries: ChDrumTickEntry[],
  resolution: number
): ChartNote[] {
  const lanesByTick = new Map<number, number[]>();

  for (const entry of entries) {
    const lane = Math.round(entry.lane);
    if (!Number.isFinite(lane)) continue;
    const lanes = lanesByTick.get(entry.tick) ?? [];
    lanes.push(lane);
    lanesByTick.set(entry.tick, lanes);
  }

  const notes: ChartNote[] = [];

  for (const [tick, lanes] of [...lanesByTick.entries()].sort((a, b) => a[0] - b[0])) {
    const set = new Set(lanes);

    for (const baseLane of CH_BASE_LANES) {
      if (!set.has(baseLane)) continue;

      const isCymbal = set.has(baseLane + CH_CYMBAL_OFFSET);
      let strength: ChartNote["Strength"] = 1;
      if (set.has(baseLane + CH_STRONG_OFFSET)) strength = 2;
      else if (set.has(baseLane + CH_LIGHT_OFFSET)) strength = 0;

      notes.push({
        Beat: tick / resolution,
        Id: getInstrumentId(baseLane, isCymbal),
        Strength: strength,
      });
    }
  }

  return notes;
}

/**
 * Indies meta Id → CH ExpertDrums lane numbers for one note at a tick.
 * Cymbal/hi-hat notes emit base pad + cymbal flag (base + 64).
 */
export function indiesNoteToChLanes(note: ChartNote): number[] {
  const lane = DRUM_LANES.find((l) => l.id === note.Id && l.chExport);
  if (!lane) return [];

  const lanes = [lane.chLane];
  if (lane.chCymbal) lanes.push(lane.chLane + CH_CYMBAL_OFFSET);

  if (note.Strength === 2) lanes.push(lane.chLane + CH_STRONG_OFFSET);
  else if (note.Strength === 0) lanes.push(lane.chLane + CH_LIGHT_OFFSET);

  return lanes;
}

import type { ChartNote, Difficulty, MetaJson } from "../types/meta";

export function clampDrumId(id: number): ChartNote["Id"] {
  return Math.max(0, Math.min(5, Math.round(id))) as ChartNote["Id"];
}

export function clampDrumStrength(strength: number): ChartNote["Strength"] {
  return Math.max(0, Math.min(2, Math.round(strength))) as ChartNote["Strength"];
}

function readNoteField(
  raw: Partial<ChartNote> & Record<string, unknown>,
  ...keys: string[]
): number | undefined {
  for (const key of keys) {
    const value = raw[key];
    if (value != null && Number.isFinite(Number(value))) return Number(value);
  }
  return undefined;
}

export function normalizeChartNote(raw: Partial<ChartNote>): ChartNote | null {
  const extended = raw as Partial<ChartNote> & Record<string, unknown>;
  const beat = readNoteField(extended, "Beat", "beat");
  const id = readNoteField(extended, "Id", "id");
  if (beat == null || id == null) return null;

  return {
    Beat: Math.max(0, beat),
    Strength: clampDrumStrength(readNoteField(extended, "Strength", "strength") ?? 1),
    Id: clampDrumId(id),
  };
}

export function normalizeChartNotes(raw: unknown): ChartNote[] {
  if (!Array.isArray(raw)) return [];

  return raw
    .map((entry) => normalizeChartNote(entry as Partial<ChartNote>))
    .filter((note): note is ChartNote => note !== null)
    .sort((a, b) => a.Beat - b.Beat || a.Id - b.Id || a.Strength - b.Strength);
}

export function sortChartNotes(notes: ChartNote[]): ChartNote[] {
  return [...notes].sort((a, b) => a.Beat - b.Beat || a.Id - b.Id || a.Strength - b.Strength);
}

export function extremeChartRequired(charts: Record<Difficulty, ChartNote[]>): boolean {
  return charts.extreme.length > 0;
}

export function validateIndiesCharts(charts: Record<Difficulty, ChartNote[]>): string[] {
  const issues: string[] = [];
  if (!extremeChartRequired(charts)) {
    issues.push("ChartExtreme is required — add at least one note on Extreme difficulty.");
  }
  return issues;
}

export function chartsIntoMeta(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>
): MetaJson {
  return {
    ...meta,
    ChartEasy: normalizeChartNotes(charts.easy),
    ChartNormal: normalizeChartNotes(charts.normal),
    ChartHard: normalizeChartNotes(charts.hard),
    ChartExtreme: normalizeChartNotes(charts.extreme),
  };
}

import type { ChartNote } from "../types/meta";

let audioCtx: AudioContext | null = null;
let masterGain: GainNode | null = null;

function ensureAudio(): { ctx: AudioContext; master: GainNode } {
  if (!audioCtx) {
    audioCtx = new AudioContext();
    masterGain = audioCtx.createGain();
    masterGain.connect(audioCtx.destination);
  }
  if (audioCtx.state === "suspended") void audioCtx.resume();
  return { ctx: audioCtx, master: masterGain! };
}

function noiseBurst(
  ctx: AudioContext,
  dest: AudioNode,
  duration: number,
  gain: number,
  filterFreq?: number
) {
  const len = Math.max(1, Math.floor(ctx.sampleRate * duration));
  const buffer = ctx.createBuffer(1, len, ctx.sampleRate);
  const data = buffer.getChannelData(0);
  for (let i = 0; i < len; i++) data[i] = Math.random() * 2 - 1;

  const src = ctx.createBufferSource();
  src.buffer = buffer;
  const filter = ctx.createBiquadFilter();
  filter.type = "bandpass";
  filter.frequency.value = filterFreq ?? 1800;
  filter.Q.value = 0.7;

  const g = ctx.createGain();
  g.gain.setValueAtTime(gain, ctx.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);

  src.connect(filter);
  filter.connect(g);
  g.connect(dest);
  src.start();
  src.stop(ctx.currentTime + duration + 0.02);
}

function toneDrop(
  ctx: AudioContext,
  dest: AudioNode,
  startHz: number,
  endHz: number,
  duration: number,
  gain: number,
  type: OscillatorType = "sine"
) {
  const osc = ctx.createOscillator();
  osc.type = type;
  osc.frequency.setValueAtTime(startHz, ctx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(Math.max(20, endHz), ctx.currentTime + duration);

  const g = ctx.createGain();
  g.gain.setValueAtTime(gain, ctx.currentTime);
  g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);

  osc.connect(g);
  g.connect(dest);
  osc.start();
  osc.stop(ctx.currentTime + duration + 0.02);
}

/** Synthesized Indies drum preview — editor only */
export function playDrumHit(
  id: ChartNote["Id"],
  strength: ChartNote["Strength"],
  volume: number
): void {
  if (volume <= 0) return;

  const { ctx, master } = ensureAudio();
  master.gain.value = volume;
  const t = ctx.currentTime;
  const vel = 0.35 + strength * 0.22;

  const bus = ctx.createGain();
  bus.gain.value = 1;
  bus.connect(master);

  switch (id) {
    case 0: // Bass kick
      toneDrop(ctx, bus, 140, 48, 0.22, vel * 1.1, "sine");
      noiseBurst(ctx, bus, 0.04, vel * 0.25, 120);
      break;
    case 1: // Snare
      noiseBurst(ctx, bus, 0.14, vel * 0.95, 2200);
      toneDrop(ctx, bus, 220, 160, 0.06, vel * 0.35, "triangle");
      break;
    case 2: // Cymbal
      noiseBurst(ctx, bus, 0.55, vel * 0.7, 6800);
      noiseBurst(ctx, bus, 0.35, vel * 0.35, 12000);
      break;
    case 3: // Tom
      toneDrop(ctx, bus, 180, 90, 0.18, vel * 0.9, "sine");
      break;
    case 4: // Hi-hat
      noiseBurst(ctx, bus, strength === 0 ? 0.035 : 0.07, vel * 0.65, strength === 0 ? 9000 : 6500);
      break;
    case 5: // Clapfire
      noiseBurst(ctx, bus, 0.05, vel * 0.5, 1400);
      noiseBurst(ctx, bus, 0.08, vel * 0.55, 2800);
      toneDrop(ctx, bus, 900, 400, 0.04, vel * 0.2, "square");
      break;
    default:
      noiseBurst(ctx, bus, 0.08, vel * 0.5, 2000);
  }

  // Tiny click for articulation
  const click = ctx.createOscillator();
  click.type = "square";
  click.frequency.value = 1200;
  const clickGain = ctx.createGain();
  clickGain.gain.setValueAtTime(vel * 0.04, t);
  clickGain.gain.exponentialRampToValueAtTime(0.001, t + 0.012);
  click.connect(clickGain);
  clickGain.connect(bus);
  click.start(t);
  click.stop(t + 0.015);
}

import JSZip from "jszip";
import type { ChartNote, Difficulty, MetaJson } from "../types/meta";
import { chartsFromMeta, parseMetaJson, prepareMetaForExport } from "./metaIO";
import { serializeMetaJson } from "./metaSerialize";
import {
  INDIES_AUDIO_FILE,
  INDIES_COVER_FILE,
  INDIES_COVER_SIZE,
  INDIES_PREVIEW_FILE,
  INDIES_PREVIEW_SAMPLE_RATE,
  INDIES_PREVIEW_SECONDS,
} from "./audioFormat";

const ZIP_MAGIC = [0x50, 0x4b, 0x03, 0x04] as const;

export type IndiesPackage = {
  meta: MetaJson;
  charts: Record<Difficulty, ChartNote[]>;
  audioFile: File | null;
  coverFile: File | null;
};

function writeAscii(view: DataView, offset: number, text: string) {
  for (let i = 0; i < text.length; i++) {
    view.setUint8(offset + i, text.charCodeAt(i));
  }
}

function encodeWavPcm16(samples: Float32Array, sampleRate: number): ArrayBuffer {
  const byteLength = samples.length * 2;
  const buffer = new ArrayBuffer(44 + byteLength);
  const view = new DataView(buffer);

  writeAscii(view, 0, "RIFF");
  view.setUint32(4, 36 + byteLength, true);
  writeAscii(view, 8, "WAVE");
  writeAscii(view, 12, "fmt ");
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true);
  view.setUint16(22, 1, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, sampleRate * 2, true);
  view.setUint16(32, 2, true);
  view.setUint16(34, 16, true);
  writeAscii(view, 36, "data");
  view.setUint32(40, byteLength, true);

  let offset = 44;
  for (let i = 0; i < samples.length; i++) {
    const sample = Math.max(-1, Math.min(1, samples[i]));
    view.setInt16(offset, sample < 0 ? sample * 0x8000 : sample * 0x7fff, true);
    offset += 2;
  }

  return buffer;
}

function resampleMonoClip(
  buffer: AudioBuffer,
  startSeconds: number,
  durationSeconds: number,
  outputRate: number
): Float32Array {
  const sourceRate = buffer.sampleRate;
  const startFrame = Math.max(0, Math.floor(startSeconds * sourceRate));
  const availableFrames = Math.max(0, buffer.length - startFrame);
  const sourceFrames = Math.min(Math.floor(durationSeconds * sourceRate), availableFrames);
  const outputFrames = Math.floor(durationSeconds * outputRate);
  const channel = buffer.getChannelData(0);
  const output = new Float32Array(outputFrames);

  if (sourceFrames <= 0 || outputFrames <= 0) return output;

  for (let i = 0; i < outputFrames; i++) {
    const sourcePos = (i * sourceRate) / outputRate;
    if (sourcePos >= sourceFrames - 1) {
      output[i] = channel[startFrame + sourceFrames - 1] ?? 0;
      continue;
    }
    const index = Math.floor(sourcePos);
    const frac = sourcePos - index;
    const a = channel[startFrame + index] ?? 0;
    const b = channel[startFrame + index + 1] ?? a;
    output[i] = a + (b - a) * frac;
  }

  return output;
}

export function buildPreviewWav(audioBuffer: AudioBuffer): ArrayBuffer {
  const samples = resampleMonoClip(
    audioBuffer,
    0,
    INDIES_PREVIEW_SECONDS,
    INDIES_PREVIEW_SAMPLE_RATE
  );
  return encodeWavPcm16(samples, INDIES_PREVIEW_SAMPLE_RATE);
}

function loadImageElement(url: string): Promise<HTMLImageElement> {
  return new Promise((resolve, reject) => {
    const image = new Image();
    image.onload = () => resolve(image);
    image.onerror = () => reject(new Error("Could not load cover image."));
    image.src = url;
  });
}

export async function imageFileToCoverPng(file: File): Promise<Blob> {
  const url = URL.createObjectURL(file);
  try {
    const image = await loadImageElement(url);
    const canvas = document.createElement("canvas");
    canvas.width = INDIES_COVER_SIZE;
    canvas.height = INDIES_COVER_SIZE;
    const ctx = canvas.getContext("2d");
    if (!ctx) throw new Error("Could not prepare cover image.");

    const scale = Math.max(
      INDIES_COVER_SIZE / image.width,
      INDIES_COVER_SIZE / image.height
    );
    const drawW = image.width * scale;
    const drawH = image.height * scale;
    const drawX = (INDIES_COVER_SIZE - drawW) / 2;
    const drawY = (INDIES_COVER_SIZE - drawH) / 2;

    ctx.fillStyle = "#000000";
    ctx.fillRect(0, 0, INDIES_COVER_SIZE, INDIES_COVER_SIZE);
    ctx.drawImage(image, drawX, drawY, drawW, drawH);

    const blob = await new Promise<Blob | null>((resolve) => {
      canvas.toBlob(resolve, "image/png");
    });
    if (!blob) throw new Error("Could not encode cover image.");
    return blob;
  } finally {
    URL.revokeObjectURL(url);
  }
}

export function sanitizeIndiesFilename(name: string): string {
  const trimmed = name.trim() || "Untitled Song";
  const cleaned = trimmed.replace(/[<>:"/\\|?*\u0000-\u001f]/g, "").replace(/\s+/g, " ");
  return cleaned || "Untitled Song";
}

export function isIndiesFile(file: File): boolean {
  const lower = file.name.toLowerCase();
  return lower.endsWith(".indies") || lower.endsWith(".indie");
}

export function isZipArchive(bytes: Uint8Array): boolean {
  return ZIP_MAGIC.every((value, index) => bytes[index] === value);
}

export async function buildIndiesZip(options: {
  meta: MetaJson;
  charts: Record<Difficulty, ChartNote[]>;
  audioFile: File;
  coverFile: File | null;
  audioBuffer: AudioBuffer;
}): Promise<Blob> {
  const { meta, charts, audioFile, coverFile, audioBuffer } = options;
  const built = prepareMetaForExport(meta, charts);
  built.FilePath = "";

  const zip = new JSZip();
  zip.file("meta.json", serializeMetaJson(built));
  zip.file(INDIES_AUDIO_FILE, await audioFile.arrayBuffer());

  if (coverFile) {
    zip.file(INDIES_COVER_FILE, await imageFileToCoverPng(coverFile));
  }

  zip.file(INDIES_PREVIEW_FILE, buildPreviewWav(audioBuffer));
  return zip.generateAsync({ type: "blob", compression: "DEFLATE" });
}

export function downloadIndiesPackage(blob: Blob, filename: string): void {
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  link.click();
  URL.revokeObjectURL(url);
}

export async function parseIndiesFile(file: File): Promise<IndiesPackage | null> {
  const bytes = new Uint8Array(await file.arrayBuffer());
  if (!isIndiesFile(file) && !isZipArchive(bytes)) return null;

  try {
    const zip = await JSZip.loadAsync(bytes);
    const metaEntry = zip.file("meta.json");
    if (!metaEntry) return null;

    const meta = parseMetaJson(await metaEntry.async("string"));
    const charts = chartsFromMeta(meta);

    let audioFile: File | null = null;
    const audioEntry = zip.file(INDIES_AUDIO_FILE);
    if (audioEntry) {
      const audioBlob = await audioEntry.async("blob");
      audioFile = new File([audioBlob], INDIES_AUDIO_FILE, {
        type: audioBlob.type || "audio/ogg",
      });
    }

    let coverFile: File | null = null;
    const coverEntry = zip.file(INDIES_COVER_FILE);
    if (coverEntry) {
      const coverBlob = await coverEntry.async("blob");
      coverFile = new File([coverBlob], INDIES_COVER_FILE, {
        type: coverBlob.type || "image/png",
      });
    }

    return { meta, charts, audioFile, coverFile };
  } catch {
    return null;
  }
}

import type { ChartNote, Difficulty, MetaJson, SongPhase, TimingAnchor } from "../types/meta";
import {
  clampPhaseId,
  clampPower,
  phaseById,
  sortSongPhases,
} from "../types/meta";
import { normalizeChartNotes, sortChartNotes } from "./chartNotes";
import { getSongOffset } from "./offset";
import { serializeMetaJson } from "./metaSerialize";
import { sortTimingAnchors } from "./timing";

function normalizeSongPhase(raw: Partial<SongPhase>): SongPhase {
  const phase = clampPhaseId(raw.phase ?? 1);
  return {
    beat: raw.beat ?? 0,
    phase,
    power: clampPower(raw.power ?? 1),
    phaseName: raw.phaseName?.trim() || phaseById(phase).label,
  };
}

export function createEmptyMeta(): MetaJson {
  return {
    NameArtist: "Unknown Artist",
    NameSong: "Untitled Song",
    NameCharter: "Chart Editor",
    FilePath: "",
    SongOffsetSeconds: 0,
    SongTiming: [
      { beat: 0, timer: 0 },
      { beat: 4, timer: 2 },
    ],
    SongPhases: [{ beat: 0, phase: 1, power: 1, phaseName: "Intro" }],
    ChartEasy: [],
    ChartNormal: [],
    ChartHard: [],
    ChartExtreme: [],
  };
}

export function chartsFromMeta(meta: MetaJson): Record<Difficulty, ChartNote[]> {
  return {
    easy: [...meta.ChartEasy],
    normal: [...meta.ChartNormal],
    hard: [...meta.ChartHard],
    extreme: [...meta.ChartExtreme],
  };
}

export function buildMetaJson(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>
): MetaJson {
  return {
    ...meta,
    SongTiming: [...meta.SongTiming].sort((a, b) => a.beat - b.beat),
    SongPhases: sortSongPhases(meta.SongPhases),
    ChartEasy: sortChartNotes(normalizeChartNotes(charts.easy)),
    ChartNormal: sortChartNotes(normalizeChartNotes(charts.normal)),
    ChartHard: sortChartNotes(normalizeChartNotes(charts.hard)),
    ChartExtreme: sortChartNotes(normalizeChartNotes(charts.extreme)),
  };
}

function bakeOffsetIntoTiming(
  timing: TimingAnchor[],
  offsetSeconds: number
): TimingAnchor[] {
  const sorted = sortTimingAnchors(timing);
  if (sorted.length === 0) return [{ beat: 0, timer: offsetSeconds }];

  const [first, ...rest] = sorted;
  if (first.beat === 0) {
    return [{ beat: 0, timer: offsetSeconds }, ...rest];
  }
  return [{ beat: 0, timer: offsetSeconds }, ...sorted];
}

export function withOffsetInTiming(
  timing: TimingAnchor[],
  offsetSeconds: number
): TimingAnchor[] {
  return bakeOffsetIntoTiming(timing, offsetSeconds);
}

/** Offset is editor-only — bake into SongTiming[0].timer and zero SongOffsetSeconds on export. */
export function prepareMetaForExport(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>
): MetaJson {
  const offset = getSongOffset(meta);
  return buildMetaJson(
    {
      ...meta,
      SongOffsetSeconds: 0,
      SongTiming: bakeOffsetIntoTiming(meta.SongTiming, offset),
    },
    charts
  );
}

export function downloadMetaJson(meta: MetaJson, filename = "meta.json"): void {
  const blob = new Blob([serializeMetaJson(meta)], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  link.click();
  URL.revokeObjectURL(url);
}

export function parseMetaJson(raw: string): MetaJson {
  const data = JSON.parse(raw) as Partial<MetaJson>;
  const base = createEmptyMeta();
  const timing =
    data.SongTiming && data.SongTiming.length >= 2
      ? sortTimingAnchors(data.SongTiming)
      : base.SongTiming;
  const songOffset = getSongOffset({
    SongOffsetSeconds: data.SongOffsetSeconds ?? 0,
    SongTiming: timing,
  });

  return {
    NameArtist: data.NameArtist ?? base.NameArtist,
    NameSong: data.NameSong ?? base.NameSong,
    NameCharter: data.NameCharter ?? base.NameCharter,
    FilePath: data.FilePath ?? "",
    SongOffsetSeconds: songOffset,
    SongTiming: bakeOffsetIntoTiming(timing, songOffset),
    SongPhases:
      data.SongPhases && data.SongPhases.length >= 1
        ? sortSongPhases(data.SongPhases.map(normalizeSongPhase))
        : base.SongPhases,
    ChartEasy: normalizeChartNotes(data.ChartEasy),
    ChartNormal: normalizeChartNotes(data.ChartNormal),
    ChartHard: normalizeChartNotes(data.ChartHard),
    ChartExtreme: normalizeChartNotes(data.ChartExtreme),
  };
}

import type { ChartNote, MetaJson, SongPhase, TimingAnchor } from "../types/meta";

const META_FIELD_ORDER: (keyof MetaJson)[] = [
  "NameArtist",
  "NameSong",
  "NameCharter",
  "FilePath",
  "SongOffsetSeconds",
  "SongTiming",
  "SongPhases",
  "ChartEasy",
  "ChartNormal",
  "ChartHard",
  "ChartExtreme",
];

function jsonString(value: string): string {
  return JSON.stringify(value);
}

/** Chart notes & song phases: `12.0` for whole beats. */
function formatDecimalBeat(beat: number): string {
  if (Number.isInteger(beat)) return `${beat}.0`;
  return String(beat);
}

/** SongTiming beats stay as integers when whole. */
function formatTimingBeat(beat: number): string {
  if (Number.isInteger(beat)) return String(beat);
  return String(beat);
}

function formatTimer(timer: number): string {
  if (timer === 0) return "0.0";
  return String(timer);
}

function formatOffset(seconds: number): string {
  if (Number.isInteger(seconds)) return `${seconds}.0`;
  return String(seconds);
}

function serializeTimingAnchor(anchor: TimingAnchor): string {
  return [
    "        {",
    `            "beat": ${formatTimingBeat(anchor.beat)},`,
    `            "timer": ${formatTimer(anchor.timer)}`,
    "        }",
  ].join("\n");
}

function serializeSongPhase(phase: SongPhase): string {
  return [
    "        {",
    `            "beat": ${formatDecimalBeat(phase.beat)},`,
    `            "phase": ${phase.phase},`,
    `            "power": ${phase.power},`,
    `            "phaseName": ${jsonString(phase.phaseName)}`,
    "        }",
  ].join("\n");
}

function serializeChartNote(note: ChartNote): string {
  return [
    "        {",
    `            "Beat": ${formatDecimalBeat(note.Beat)},`,
    `            "Strength": ${note.Strength},`,
    `            "Id": ${note.Id}`,
    "        }",
  ].join("\n");
}

function serializeObjectArray<T>(items: T[], serializeItem: (item: T) => string): string {
  if (items.length === 0) return "[]";
  return `[\n${items.map(serializeItem).join(",\n")}\n    ]`;
}

/** Serialize meta.json matching Stacked Actors / official Indies layout. */
export function serializeMetaJson(meta: MetaJson): string {
  const lines: string[] = ["{"];

  META_FIELD_ORDER.forEach((key, index) => {
    const trailing = index < META_FIELD_ORDER.length - 1 ? "," : "";

    switch (key) {
      case "NameArtist":
      case "NameSong":
      case "NameCharter":
      case "FilePath":
        lines.push(`    "${key}": ${jsonString(meta[key])}${trailing}`);
        break;
      case "SongOffsetSeconds":
        lines.push(`    "${key}": ${formatOffset(meta.SongOffsetSeconds)}${trailing}`);
        break;
      case "SongTiming":
        lines.push(
          `    "${key}": ${serializeObjectArray(meta.SongTiming, serializeTimingAnchor)}${trailing}`
        );
        break;
      case "SongPhases":
        lines.push(
          `    "${key}": ${serializeObjectArray(meta.SongPhases, serializeSongPhase)}${trailing}`
        );
        break;
      case "ChartEasy":
        lines.push(
          `    "${key}": ${serializeObjectArray(meta.ChartEasy, serializeChartNote)}${trailing}`
        );
        break;
      case "ChartNormal":
        lines.push(
          `    "${key}": ${serializeObjectArray(meta.ChartNormal, serializeChartNote)}${trailing}`
        );
        break;
      case "ChartHard":
        lines.push(
          `    "${key}": ${serializeObjectArray(meta.ChartHard, serializeChartNote)}${trailing}`
        );
        break;
      case "ChartExtreme":
        lines.push(
          `    "${key}": ${serializeObjectArray(meta.ChartExtreme, serializeChartNote)}${trailing}`
        );
        break;
      default:
        break;
    }
  });

  lines.push("}");
  return `${lines.join("\n")}\n`;
}

import type { ChartNote } from "../types/meta";
import { sortChartNotes } from "./chartNotes";
import { beatToTick, RESOLUTION, snapBeat } from "./resolution";

export const NOTE_CLIPBOARD_MARKER = "drumeditor-notes";

export type NoteClipboardPayload = {
  version: 1;
  notes: ChartNote[];
  /** Beat of the earliest copied note — paste puts this on the strike bar. */
  anchorBeat: number;
};

export function selectionFirstBeat(notes: ChartNote[]): number {
  return Math.min(...notes.map((n) => n.Beat));
}

export function viewportTickRange(
  scrollTick: number,
  pixelsPerTick: number,
  canvasHeight: number,
  strikeOffset = 150,
  laneHeaderH = 44
): { minTick: number; maxTick: number } {
  const sy = canvasHeight - strikeOffset;
  const viewTop = scrollTick + Math.ceil((sy - laneHeaderH) / pixelsPerTick);
  const viewBottom =
    scrollTick - Math.ceil((canvasHeight - sy + 80) / pixelsPerTick) - RESOLUTION;
  return {
    minTick: Math.max(0, viewBottom),
    maxTick: Math.max(0, viewTop),
  };
}

export function notesInTickRange(
  notes: ChartNote[],
  minTick: number,
  maxTick: number
): ChartNote[] {
  const lo = Math.min(minTick, maxTick);
  const hi = Math.max(minTick, maxTick);
  return notes.filter((note) => {
    const tick = beatToTick(note.Beat);
    return tick >= lo && tick <= hi;
  });
}

export function shiftNotes(notes: ChartNote[], beatDelta: number): ChartNote[] {
  return notes.map((note) => ({
    ...note,
    Beat: Math.max(0, Math.round((note.Beat + beatDelta) * 1000) / 1000),
  }));
}

export function mergeNotes(existing: ChartNote[], incoming: ChartNote[]): ChartNote[] {
  const byCell = new Map<string, ChartNote>();
  for (const note of existing) {
    byCell.set(`${beatToTick(note.Beat)}:${note.Id}`, note);
  }
  for (const note of incoming) {
    byCell.set(`${beatToTick(note.Beat)}:${note.Id}`, note);
  }
  return sortChartNotes([...byCell.values()]);
}

export function serializeClipboard(payload: NoteClipboardPayload): string {
  return JSON.stringify({ [NOTE_CLIPBOARD_MARKER]: payload.version, ...payload });
}

export function parseClipboard(text: string): NoteClipboardPayload | null {
  try {
    const data = JSON.parse(text) as Partial<NoteClipboardPayload> & Record<string, unknown>;
    if (data[NOTE_CLIPBOARD_MARKER] !== 1) return null;
    if (!Array.isArray(data.notes) || data.notes.length === 0) return null;
    const notes = data.notes
      .map((raw) => {
        const note = raw as Partial<ChartNote>;
        if (note.Beat == null || note.Id == null) return null;
        return {
          Beat: Math.max(0, Number(note.Beat)),
          Id: Math.max(0, Math.min(5, Math.round(Number(note.Id)))) as ChartNote["Id"],
          Strength: Math.max(0, Math.min(2, Math.round(Number(note.Strength ?? 1)))) as ChartNote["Strength"],
        };
      })
      .filter((note): note is ChartNote => note !== null);
    if (notes.length === 0) return null;
    const anchorBeat =
      typeof data.anchorBeat === "number"
        ? data.anchorBeat
        : selectionFirstBeat(notes);
    return { version: 1, notes, anchorBeat };
  } catch {
    return null;
  }
}

export function pastePayloadAtBeat(
  payload: NoteClipboardPayload,
  strikeBeat: number,
  snapTicks: number
): ChartNote[] {
  const target = snapBeat(strikeBeat, snapTicks);
  return shiftNotes(payload.notes, target - payload.anchorBeat);
}

import type { MetaJson } from "../types/meta";
import { sortTimingAnchors } from "./timing";

export const OFFSET_NUDGE_FINE_MS = 10;
export const OFFSET_NUDGE_COARSE_MS = 100;

/**
 * Silent lead-in before beat 0 hits — may live in SongTiming[0].timer (Indies/meta)
 * or [Song].Offset (Clone Hero .chart). Use the larger value when both are present.
 */
export function getSongOffset(meta: Pick<MetaJson, "SongOffsetSeconds" | "SongTiming">): number {
  const sorted = sortTimingAnchors(meta.SongTiming);
  const first = sorted[0];
  const timingOffset = first?.beat === 0 ? first.timer : 0;
  return Math.max(timingOffset, meta.SongOffsetSeconds);
}

export function offsetToMs(seconds: number): number {
  return Math.round(seconds * 1000);
}

export function offsetFromMs(ms: number): number {
  return ms / 1000;
}

/** Chart time is in the silent lead-in before audio begins */
export function isInSilentLeadIn(chartTime: number, offsetSeconds: number): boolean {
  return chartTime < offsetSeconds;
}

/** Chart timeline → audio element position (0 during silent lead-in) */
export function chartToAudioTime(chartTime: number, offsetSeconds: number): number {
  if (chartTime < offsetSeconds) return 0;
  return chartTime - offsetSeconds;
}

/** Audio file position → chart timeline */
export function audioToChartTime(audioTime: number, offsetSeconds: number): number {
  return audioTime + offsetSeconds;
}

/** Clone Hero / Moonscraper standard chart resolution */
export const RESOLUTION = 480;
export const BEATS_PER_MEASURE = 4;
export const TICKS_PER_MEASURE = RESOLUTION * BEATS_PER_MEASURE;

/** Moonscraper-style grid: always draw 1/8 lines; snap only changes placement. */
export const VISUAL_GRID_TICKS = 240;

/** Default zoom — 64px per 1/8 row at startup. */
export const FIXED_PIXELS_PER_TICK = 64 / VISUAL_GRID_TICKS;

export const MIN_PIXELS_PER_TICK = 0.12;
export const MAX_PIXELS_PER_TICK = 2;

export function clampPixelsPerTick(ppt: number): number {
  return Math.max(MIN_PIXELS_PER_TICK, Math.min(MAX_PIXELS_PER_TICK, ppt));
}

/** Visual 1/8 row height — snap only affects placement, not zoom. */
export function visualGridRowPixels(pixelsPerTick: number): number {
  return VISUAL_GRID_TICKS * pixelsPerTick;
}

export const SNAP_OPTIONS = [
  { ticks: 480, label: "1/4 (Beat)" },
  { ticks: 240, label: "1/8" },
  { ticks: 120, label: "1/16" },
  { ticks: 60, label: "1/32" },
  { ticks: 30, label: "1/64" },
  { ticks: TICKS_PER_MEASURE, label: "1/1 (Measure)" },
] as const;

export function beatToTick(beat: number): number {
  return Math.round(beat * RESOLUTION);
}

export function tickToBeat(tick: number): number {
  return tick / RESOLUTION;
}

export function snapTick(rawTick: number, snapTicks: number): number {
  if (snapTicks <= 0) return Math.max(0, Math.round(rawTick));
  return Math.max(0, Math.round(rawTick / snapTicks) * snapTicks);
}

export function snapBeat(beat: number, snapTicks: number): number {
  return tickToBeat(snapTick(beatToTick(beat), snapTicks));
}

export function beatsEqual(a: number, b: number): boolean {
  return beatToTick(a) === beatToTick(b);
}

export function formatTick(tick: number): string {
  const measure = Math.floor(tick / TICKS_PER_MEASURE);
  const beatInMeasure = Math.floor((tick % TICKS_PER_MEASURE) / RESOLUTION);
  const sub = tick % RESOLUTION;
  if (sub === 0) return `M${measure}:B${beatInMeasure}`;
  return `M${measure}:B${beatInMeasure}+${sub}`;
}

import type { ChartNote, Difficulty, MetaJson } from "../types/meta";
import { getSongOffset } from "./offset";
import { RESOLUTION } from "./resolution";
import { maxContentBeat, timeToBeat } from "./timing";

const MIN_BEATS = 8;
const END_PADDING_BEATS = 4;

export function songExtentTicks(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>,
  duration: number
): number {
  let maxBeat = Math.max(maxContentBeat(meta, charts), MIN_BEATS);

  if (duration > 0) {
    const endBeat = timeToBeat(duration + getSongOffset(meta), meta.SongTiming);
    maxBeat = Math.max(maxBeat, endBeat);
  }

  return Math.ceil((maxBeat + END_PADDING_BEATS) * RESOLUTION);
}

import type { ChartNote, Difficulty, MetaJson } from "../types/meta";

const DIFFICULTY_ORDER: Difficulty[] = ["extreme", "hard", "normal", "easy"];

/** Clone Hero / Moonscraper song.ini difficulty rating (0 = none, 4 = expert). */
const CH_DIFFICULTY_RATING: Record<Difficulty, number> = {
  easy: 1,
  normal: 2,
  hard: 3,
  extreme: 4,
};

function highestDrumDifficulty(charts: Record<Difficulty, ChartNote[]>): number {
  for (const difficulty of DIFFICULTY_ORDER) {
    if (charts[difficulty].length > 0) {
      return CH_DIFFICULTY_RATING[difficulty];
    }
  }
  return 0;
}

function iniLine(key: string, value: string | number): string {
  return `${key} = ${value}`;
}

/**
 * Clone Hero song.ini — matches Indies TCBAITW layout and Moonscraper export tags.
 * Offset is baked into notes.chart / meta timing, so delay stays 0.
 */
export function buildSongIni(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>,
  duration = 0
): string {
  const diffRating = highestDrumDifficulty(charts);
  const songLengthMs = duration > 0 ? Math.round(duration * 1000) : 0;

  const lines = [
    "[song]",
    iniLine("name", meta.NameSong.trim() || "Untitled Song"),
    iniLine("artist", meta.NameArtist.trim() || "Unknown Artist"),
    iniLine("album", ""),
    iniLine("genre", "rock"),
    iniLine("year", ""),
    iniLine("song_length", songLengthMs),
    iniLine("charter", meta.NameCharter.trim() || "Chart Editor"),
    iniLine("diff_band", diffRating),
    iniLine("diff_guitar", diffRating),
    iniLine("diff_rhythm", diffRating),
    iniLine("diff_bass", diffRating),
    iniLine("diff_drums", diffRating),
    iniLine("diff_keys", diffRating),
    iniLine("diff_guitarghl", diffRating),
    iniLine("diff_bassghl", diffRating),
    iniLine("diff_rhythmghl", diffRating),
    iniLine("preview_start_time", 0),
    iniLine("icon", 0),
    iniLine("playlist_track", ""),
    iniLine("track", ""),
    iniLine("album_track", ""),
    iniLine("delay", 0),
    iniLine("loading_phrase", ""),
    "",
  ];

  return lines.join("\n");
}

function downloadTextFile(content: string, filename: string): void {
  const blob = new Blob([content], { type: "text/plain;charset=utf-8" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = filename;
  link.click();
  URL.revokeObjectURL(url);
}

export function downloadSongIni(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>,
  duration = 0,
  filename = "song.ini"
): void {
  downloadTextFile(buildSongIni(meta, charts, duration), filename);
}

import type { ChartNote, Difficulty, MetaJson, TimingAnchor } from "../types/meta";

export function sortTimingAnchors(anchors: TimingAnchor[]): TimingAnchor[] {
  return [...anchors].sort((a, b) => a.beat - b.beat || a.timer - b.timer);
}

export function beatToTime(beat: number, anchors: TimingAnchor[]): number {
  if (anchors.length === 0) return 0;
  const sorted = [...anchors].sort((a, b) => a.beat - b.beat);

  if (beat <= sorted[0].beat) {
    if (sorted.length < 2) return sorted[0].timer;
    const [a, b] = sorted;
    return a.timer + ((beat - a.beat) * (b.timer - a.timer)) / (b.beat - a.beat);
  }

  for (let i = 0; i < sorted.length - 1; i++) {
    const a = sorted[i];
    const b = sorted[i + 1];
    if (beat >= a.beat && beat <= b.beat) {
      const ratio = (beat - a.beat) / (b.beat - a.beat);
      return a.timer + ratio * (b.timer - a.timer);
    }
  }

  const last = sorted[sorted.length - 1];
  const prev = sorted[sorted.length - 2];
  return last.timer + ((beat - last.beat) * (last.timer - prev.timer)) / (last.beat - prev.beat);
}

export function timeToBeat(time: number, anchors: TimingAnchor[]): number {
  if (anchors.length === 0) return 0;
  const sorted = [...anchors].sort((a, b) => a.beat - b.beat);

  if (time <= sorted[0].timer) {
    if (sorted.length < 2) return sorted[0].beat;
    const [a, b] = sorted;
    return a.beat + ((time - a.timer) * (b.beat - a.beat)) / (b.timer - a.timer);
  }

  for (let i = 0; i < sorted.length - 1; i++) {
    const a = sorted[i];
    const b = sorted[i + 1];
    if (time >= a.timer && time <= b.timer) {
      const ratio = (time - a.timer) / (b.timer - a.timer);
      return a.beat + ratio * (b.beat - a.beat);
    }
  }

  const last = sorted[sorted.length - 1];
  const prev = sorted[sorted.length - 2];
  return last.beat + ((time - last.timer) * (last.beat - prev.beat)) / (last.timer - prev.timer);
}

export function bpmFromAnchors(anchors: TimingAnchor[]): number {
  const sorted = [...anchors].sort((a, b) => a.beat - b.beat);
  if (sorted.length < 2) return 120;
  const span = sorted[1].timer - sorted[0].timer;
  const beats = sorted[1].beat - sorted[0].beat;
  if (span <= 0 || beats <= 0) return 120;
  return (beats / span) * 60;
}

export function anchorsFromBpm(bpm: number): TimingAnchor[] {
  const spb = 60 / bpm;
  return [
    { beat: 0, timer: 0 },
    { beat: 4, timer: 4 * spb },
  ];
}

export function bpmAtAnchor(anchors: TimingAnchor[], index: number): number {
  const sorted = sortTimingAnchors(anchors);
  if (sorted.length < 2) return 120;

  if (index < sorted.length - 1) {
    const a = sorted[index];
    const b = sorted[index + 1];
    const span = b.timer - a.timer;
    const beats = b.beat - a.beat;
    if (span > 0 && beats > 0) return (beats / span) * 60;
  }

  if (index > 0) {
    const a = sorted[index - 1];
    const b = sorted[index];
    const span = b.timer - a.timer;
    const beats = b.beat - a.beat;
    if (span > 0 && beats > 0) return (beats / span) * 60;
  }

  return 120;
}

export function maxContentBeat(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>
): number {
  let max = 0;
  for (const anchor of meta.SongTiming) max = Math.max(max, anchor.beat);
  for (const phase of meta.SongPhases) max = Math.max(max, phase.beat);
  for (const notes of Object.values(charts)) {
    for (const note of notes) max = Math.max(max, note.Beat);
  }
  return max;
}

/** Ensure a closing anchor exists through the last charted beat. */
export function ensureEndAnchor(
  anchors: TimingAnchor[],
  endBeat: number
): TimingAnchor[] {
  const sorted = sortTimingAnchors(anchors);
  if (sorted.length === 0) return anchorsFromBpm(120);

  const last = sorted[sorted.length - 1];
  if (last.beat >= endBeat - 1 / 480) return sorted;

  return [
    ...sorted,
    { beat: endBeat, timer: beatToTime(endBeat, sorted) },
  ];
}

/** Collapse per-beat anchors into tempo-change points for [SyncTrack]. */
export function simplifyAnchorsForSync(
  anchors: TimingAnchor[],
  toleranceBpm = 0.25
): TimingAnchor[] {
  const sorted = sortTimingAnchors(anchors);
  if (sorted.length <= 2) return sorted;

  const result: TimingAnchor[] = [sorted[0]];
  let lastBpm = bpmAtAnchor(sorted, 0);

  for (let i = 1; i < sorted.length; i++) {
    const bpm = bpmAtAnchor(sorted, i);
    if (Math.abs(bpm - lastBpm) > toleranceBpm) {
      result.push(sorted[i]);
      lastBpm = bpm;
    }
  }

  const tail = sorted[sorted.length - 1];
  const prev = result[result.length - 1];
  if (Math.abs(prev.beat - tail.beat) > 1 / 480 || Math.abs(prev.timer - tail.timer) > 0.001) {
    result.push(tail);
  }

  return result.length >= 2 ? result : sorted.slice(0, 2);
}

export function prepareSyncAnchors(
  meta: MetaJson,
  charts: Record<Difficulty, ChartNote[]>
): TimingAnchor[] {
  const endBeat = Math.max(maxContentBeat(meta, charts), 4);
  return simplifyAnchorsForSync(ensureEndAnchor(meta.SongTiming, endBeat));
}

import { WAVE_WIDTH_FRAC } from "./waveform";

export { WAVE_WIDTH_FRAC };

export type WaveDrawSample = { pos: number; amp: number };

export type WaveDrawStyle = {
  /** Lane/instrument hex color — tints the envelope instead of default cyan */
  tintColor?: string;
  /** Scales envelope opacity (0–1) */
  intensity?: number;
};

function hexToRgb(hex: string): [number, number, number] {
  const n = parseInt(hex.slice(1), 16);
  return [(n >> 16) & 255, (n >> 8) & 255, n & 255];
}

function rgba(hex: string, alpha: number): string {
  const [r, g, b] = hexToRgb(hex);
  return `rgba(${r},${g},${b},${alpha})`;
}

function enrichWaveSamples(samples: WaveDrawSample[]): WaveDrawSample[] {
  if (samples.length < 2) return samples;

  const sorted = [...samples].sort((a, b) => a.pos - b.pos);
  const out: WaveDrawSample[] = [];

  for (let i = 0; i < sorted.length - 1; i++) {
    const a = sorted[i];
    const b = sorted[i + 1];
    out.push(a);

    const gap = b.pos - a.pos;
    if (gap <= 3) continue;

    const steps = Math.min(6, Math.max(2, Math.floor(gap / 3)));
    for (let s = 1; s < steps; s++) {
      const t = s / steps;
      const amp = a.amp + (b.amp - a.amp) * t;
      out.push({
        pos: a.pos + gap * t,
        amp: amp * (0.92 + 0.08 * Math.sin(t * Math.PI)),
      });
    }
  }

  out.push(sorted[sorted.length - 1]);
  return out;
}

/** Mirrored cyan envelope — shared by highway and song scrollbar */
export function drawMirroredWaveEnvelope(
  ctx: CanvasRenderingContext2D,
  samples: WaveDrawSample[],
  cx: number,
  maxHalf: number,
  mode: "past" | "future",
  style: WaveDrawStyle = {}
) {
  const tint = style.tintColor;
  const intensity = style.intensity ?? 1;
  const visible = enrichWaveSamples(
    samples
      .filter((s) => s.amp >= 0.01)
      .map((s) => ({ pos: s.pos, amp: Math.min(1, s.amp) }))
  );
  if (visible.length < 2) return;

  const halves = visible.map((sample) => ({
    pos: sample.pos,
    half: Math.max(1.25, Math.pow(sample.amp, 0.9) * maxHalf),
  }));

  const topPath = new Path2D();
  const botPath = new Path2D();
  const glowTop = new Path2D();
  const glowBot = new Path2D();

  halves.forEach((point, i) => {
    const xR = cx + point.half;
    const xL = cx - point.half;
    const gR = cx + point.half * 1.16;
    const gL = cx - point.half * 1.16;

    if (i === 0) {
      topPath.moveTo(cx, point.pos);
      botPath.moveTo(cx, point.pos);
      glowTop.moveTo(cx, point.pos);
      glowBot.moveTo(cx, point.pos);
    }
    topPath.lineTo(xR, point.pos);
    botPath.lineTo(xL, point.pos);
    glowTop.lineTo(gR, point.pos);
    glowBot.lineTo(gL, point.pos);
  });

  for (let i = halves.length - 1; i >= 0; i--) {
    topPath.lineTo(cx, halves[i].pos);
    botPath.lineTo(cx, halves[i].pos);
    glowTop.lineTo(cx, halves[i].pos);
    glowBot.lineTo(cx, halves[i].pos);
  }

  topPath.closePath();
  botPath.closePath();
  glowTop.closePath();
  glowBot.closePath();

  const minY = halves[0].pos;
  const maxY = halves[halves.length - 1].pos;

  ctx.save();
  ctx.lineJoin = "round";
  ctx.lineCap = "round";

  if (mode === "past") {
    ctx.shadowColor = tint ? rgba(tint, 0.45 * intensity) : "rgba(0, 220, 255, 0.45)";
    ctx.shadowBlur = tint ? 12 : 18;
    ctx.fillStyle = tint ? rgba(tint, 0.12 * intensity) : "rgba(0, 180, 220, 0.12)";
    ctx.fill(glowTop);
    ctx.fill(glowBot);
    ctx.shadowBlur = 0;

    const bodyGrad = ctx.createLinearGradient(cx - maxHalf, 0, cx + maxHalf, 0);
    if (tint) {
      bodyGrad.addColorStop(0, rgba(tint, 0.08 * intensity));
      bodyGrad.addColorStop(0.22, rgba(tint, 0.42 * intensity));
      bodyGrad.addColorStop(0.5, rgba(tint, 0.72 * intensity));
      bodyGrad.addColorStop(0.78, rgba(tint, 0.42 * intensity));
      bodyGrad.addColorStop(1, rgba(tint, 0.08 * intensity));
    } else {
      bodyGrad.addColorStop(0, "rgba(0, 170, 220, 0.1)");
      bodyGrad.addColorStop(0.22, "rgba(0, 230, 255, 0.55)");
      bodyGrad.addColorStop(0.5, "rgba(210, 255, 255, 0.92)");
      bodyGrad.addColorStop(0.78, "rgba(0, 230, 255, 0.55)");
      bodyGrad.addColorStop(1, "rgba(0, 170, 220, 0.1)");
    }
    ctx.fillStyle = bodyGrad;
    ctx.fill(topPath);
    ctx.fill(botPath);

    const coreGrad = ctx.createLinearGradient(cx - maxHalf * 0.35, 0, cx + maxHalf * 0.35, 0);
    if (tint) {
      coreGrad.addColorStop(0, rgba(tint, 0));
      coreGrad.addColorStop(0.5, rgba(tint, 0.38 * intensity));
      coreGrad.addColorStop(1, rgba(tint, 0));
    } else {
      coreGrad.addColorStop(0, "rgba(120, 240, 255, 0)");
      coreGrad.addColorStop(0.5, "rgba(220, 255, 255, 0.55)");
      coreGrad.addColorStop(1, "rgba(120, 240, 255, 0)");
    }
    ctx.fillStyle = coreGrad;

    const coreTop = new Path2D();
    const coreBot = new Path2D();
    halves.forEach((point, i) => {
      const coreHalf = point.half * 0.42;
      const xR = cx + coreHalf;
      const xL = cx - coreHalf;
      if (i === 0) {
        coreTop.moveTo(cx, point.pos);
        coreBot.moveTo(cx, point.pos);
      }
      coreTop.lineTo(xR, point.pos);
      coreBot.lineTo(xL, point.pos);
    });
    for (let i = halves.length - 1; i >= 0; i--) {
      coreTop.lineTo(cx, halves[i].pos);
      coreBot.lineTo(cx, halves[i].pos);
    }
    coreTop.closePath();
    coreBot.closePath();
    ctx.fill(coreTop);
    ctx.fill(coreBot);
  } else {
    const grad = ctx.createLinearGradient(cx - maxHalf, 0, cx + maxHalf, 0);
    grad.addColorStop(0, "rgba(35, 55, 80, 0.04)");
    grad.addColorStop(0.5, "rgba(65, 95, 130, 0.28)");
    grad.addColorStop(1, "rgba(35, 55, 80, 0.04)");
    ctx.fillStyle = grad;
    ctx.fill(topPath);
    ctx.fill(botPath);
  }

  ctx.restore();

  ctx.save();
  ctx.lineJoin = "round";
  ctx.lineCap = "round";
  ctx.strokeStyle = tint
    ? rgba(tint, (mode === "past" ? 0.38 : 0.18) * intensity)
    : mode === "past"
      ? "rgba(255, 210, 80, 0.42)"
      : "rgba(80, 110, 150, 0.22)";
  ctx.lineWidth = mode === "past" ? 1 : 0.65;

  ctx.beginPath();
  halves.forEach((point, i) => {
    const x = cx - point.half;
    if (i === 0) ctx.moveTo(x, point.pos);
    else ctx.lineTo(x, point.pos);
  });
  ctx.stroke();

  ctx.beginPath();
  halves.forEach((point, i) => {
    const x = cx + point.half;
    if (i === 0) ctx.moveTo(x, point.pos);
    else ctx.lineTo(x, point.pos);
  });
  ctx.stroke();
  ctx.restore();

  if (mode === "past" && !tint) {
    ctx.save();
    const spineGrad = ctx.createLinearGradient(0, minY, 0, maxY);
    spineGrad.addColorStop(0, "rgba(160, 240, 255, 0)");
    spineGrad.addColorStop(0.12, "rgba(200, 255, 255, 0.22)");
    spineGrad.addColorStop(0.5, "rgba(220, 255, 255, 0.38)");
    spineGrad.addColorStop(0.88, "rgba(200, 255, 255, 0.22)");
    spineGrad.addColorStop(1, "rgba(160, 240, 255, 0)");
    ctx.strokeStyle = spineGrad;
    ctx.lineWidth = 1;
    ctx.beginPath();
    halves.forEach((point, i) => {
      if (i === 0) ctx.moveTo(cx, point.pos);
      else ctx.lineTo(cx, point.pos);
    });
    ctx.stroke();
    ctx.restore();
  }
}

import type { TimingAnchor } from "../types/meta";
import { chartToAudioTime } from "./offset";
import { RESOLUTION, beatToTick } from "./resolution";
import { beatToTime, timeToBeat } from "./timing";

export type WavePeak = { tick: number; amp: number };

/** Mirrored envelope half-width as a fraction of container width at waveScale 1 */
export const WAVE_WIDTH_FRAC = 0.4;

function measureAtTime(
  data: Float32Array,
  duration: number,
  audioTime: number,
  window: number
): number {
  const center = Math.floor((audioTime / duration) * data.length);
  let peak = 0;
  let sumSq = 0;
  let count = 0;

  for (let i = center - window; i <= center + window; i++) {
    if (i < 0 || i >= data.length) continue;
    const v = Math.abs(data[i]);
    peak = Math.max(peak, v);
    sumSq += v * v;
    count++;
  }

  if (count === 0) return 0;
  const rms = Math.sqrt(sumSq / count);
  return peak * 0.38 + rms * 0.62;
}

function smoothPeaks(peaks: WavePeak[], radius = 2): WavePeak[] {
  if (peaks.length < 3 || radius <= 0) return peaks;

  return peaks.map((peak, i) => {
    let sum = 0;
    let weight = 0;
    for (let d = -radius; d <= radius; d++) {
      const j = i + d;
      if (j < 0 || j >= peaks.length) continue;
      const w = radius + 1 - Math.abs(d);
      sum += peaks[j].amp * w;
      weight += w;
    }
    return { tick: peak.tick, amp: weight > 0 ? sum / weight : peak.amp };
  });
}

export function buildWaveformByTick(
  buffer: AudioBuffer,
  anchors: TimingAnchor[],
  offsetSeconds: number,
  tickStep = 16
): WavePeak[] {
  const data = buffer.getChannelData(0);
  const duration = buffer.duration;
  if (duration <= 0) return [];

  const endBeat = timeToBeat(duration + offsetSeconds, anchors);
  const maxTick = beatToTick(Math.max(0, endBeat)) + RESOLUTION;
  const peaks: WavePeak[] = [];
  const secondsPerTick =
    beatToTime(tickStep / RESOLUTION, anchors) - beatToTime(0, anchors) ||
    tickStep / RESOLUTION / 2;
  const window = Math.max(
    2,
    Math.floor((data.length / duration) * secondsPerTick * 0.85)
  );

  let maxAmp = 0;
  for (let tick = 0; tick <= maxTick; tick += tickStep) {
    const chartTime = beatToTime(tick / RESOLUTION, anchors);
    if (chartTime < offsetSeconds) {
      peaks.push({ tick, amp: 0 });
      continue;
    }
    const audioTime = chartToAudioTime(chartTime, offsetSeconds);
    const amp = measureAtTime(data, duration, audioTime, window);
    maxAmp = Math.max(maxAmp, amp);
    peaks.push({ tick, amp });
  }

  if (maxAmp <= 0) return peaks;

  const normalized = peaks.map((p) => ({ tick: p.tick, amp: p.amp / maxAmp }));
  return smoothPeaks(normalized, 2);
}

